INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','守護神',NULL,NULL,'代表肖鼠，本命佛是 【千手觀音菩薩 】 ( 農唇十一月出生者之月守護佛) , 象征著大慈大悲。鼠人喜歡居住在幽静之處所。若為君子可達官顯貴,可储財富至富， 唯性格急躁。若您能隨身佩戴此物品，可默默地保佑自己順利渡過各種難關,消除各種 病痛。必使其事事順心，心想事成，當您運氣旺時,能使自己旺上加旺；當運氟低落 時,能夠消除各種障礙,使自己逢凶化吉，從而獲 得一生之幸福舆平安吉祥。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','名人堂',NULL,NULL,'{ 名人堂} 明成祖【朱棣(1 360年，庚子) 】,是明代頗有建樹之政治家，在位22年。輩固 中央集權。是「鼠」中識時務、善利用機會之典 型代表。 抗倭名将【戚繼光(15 28年，戊子) 】,意志堅强、不屈不撓之將門世家。 【杜甫 (712年，壬子) 】唐代詩人。自幼好學不倦，6嵗時就能吟詩作賦,表現 出卓越之文學才華。但一生屢屢被奸相愚弄，懷才不遇 ，仕途失意。雖然如此，始終没 有放棄對生活之信心。 【上官婉兒( 664年，甲子年) 】,開朗、活潑、樂觀、善交際之唐代女詩人。武 則天命任「巾幅首相。。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','風水魚',NULL,NULL,'{鼠與風水魚 風水魚:——如意吉祥，此魚在紅白斑上塗有一層墨汁般之斑紋,頭部上亦有黑色 79紋，俗稱『吉祥錦鯉」。鼠人因位居生肖之首，故難免折財臨殺,紅白乃錦鯉正色。 黑在風水上有擋殺之效，因此錦鲤外可擋殺，内可納財，是保鼠人一生平顺之適。 {健康運勢} 少生病，但一旦生病就很難再爬起來,泌尿科、血液、腸胃之疾。好像 用不完之體 力和能量一旦做起事來一定要做到某個階段才會停手，常日夜顛倒，並出入娱集場所， 導致睡眠不足，煙酒過量時損害身體之主因。中風 、腳疾、神經病，男子须防水厄之 災,女子易患子宮方面之疾病',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','財運',NULL,NULL,'{財運氣勢} 財運上，若為君子可達官顯貴,若為平民可储蓄財富，金錢不乏， 剋制性格暴躁， 更能「錢途如意』。逢牛年，則分外好運,因六合之吉，在 丑 牛 丑 月運程最旺，若是開 拓事業或賺取外快大多能夠一帆風顺。 一生很少會遇到金錢上之困擾。但因您 膽小怕 事，且拘泥於一事而不知變通，故浪費了不少可賺錢之機遇，有時太吝裔 ，在該花錢之 時候將錢看得太重。其實買些禮物送給朋友是必要，絕對不是浪費。注重積蓄，衣食之 憂。中年後會得一筆可觀之積蓄，其膽小謹慎之性格決定不會將之投資股票市場,存銀 行以求得穩定之利息。後半生仍過小康生活，或比前半生過得更好。雖然没有理財之概 念和金錢投資之專業知識,但您是「開源節流』之高手。總能踏踏實實、辛辛苦苦地將 賺來之錢,一點一滴储蓄起來,不會使自己發生財政危機,從而平安度過一生。 大都會有一個幸福之童年，在青年時也有其無拘無束之生活，而且一切都很如意 到了中年，會有些麻煩之事降臨,會遇上不少之挫折。可能是在情 場上之失意，或生意 上或工作上之失敗。但晚年通常都比較幸福和快樂。','大吉',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','事業',NULL,NULL,'{事業發展} 因您靈活而柔弱之個性、執著和熱情之習慣,往往不能控制自己之理智，從而做出 不利自己',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','事業',NULL,NULL,'事業發展之事情來。可能受僥体心理之軀使，拿事業孤注一擲,最後往往會輸 得一敗塗地。似乎有一種天性， 一旦設定某 個事業目標尤其是賺錢之計劃後,就會拼命 去做，不達目的誓不甘休，這使您常能夠實現目標。在您一生中，很少會遇到金錢上之 困憂。有敏銳之觀察能力，能慧眼獨具地進行創作。可成為優秀之作家、兿術者。天真 活潑、單純膽小、不能成為頭號人物，但機警、敏捷、認真，故可當副手，能把一切安 排妥當,可成出色之秘書、公關、管理人員、游泳、跳水等水上專長,百貨流通 、娱樂 業、文教、音響師。適獨立經管餐館,從事研究、表演、醫生等。 具有正直奉獻精神，能成為優秀教師。在事業上不能有暴發戶之心理，應努 力學習 一些金錢之管理知識,學習如何利用現有之資金進行投資,只有這様才能在事業上有突 論 命 寶 罐 9 破之發展。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','職業',NULL,NULL,'{職業運勢} 您積極而有獨立性，因此可以自由發揮、不受限制之工作比擔任大公司之職員更 適合您；學者、音樂家、醫生、評論家、研究員、演整人員、個性化商場經營者、咖啡 店經營者、會計、或獨立工作不會發生任何問題，工作能順利進行。但與他人一起工作 者，易變得無創造性，故必學會舆他人配合與協調。 敏銳之直覺,一些精細之手鼕和需要細密心思之工作也非常合適您。如技巧性之 工作，處理一般事務、商品管理驗收、裝節、美化、園鼕、手工 鼕、攝影，接受這些工 作，能使其充分發揮所長,易獲最高之成就感。 終日勞碌险中求，何時雲開見日頭,若當青春勤奮鬥,老來福至免無愁。 心思細密，記憶力強,極富想像力，故應選擇需具有機智、 才幹即可發揮創作才華 之工作，會比較易獲得成功；寫作、編輯、作曲、作詞、較具獨立性質之自由業, 才能 淋漓盡致地激發您潛在之才華。 男性更傾向個人自行創業:經管餐飲業、運輸業、 服裝業、汽車買賣。女性由於其 與生俱來之温柔魅力，待人隨和、開朗，尤其善於利用時間、巨細 之事都能掌控適宜 且能做到家庭舆事業兼顧,因此適合擔任公司主管。 適合從事教師、保姆、照顧老人、兒童、病人之看護工作， 不過,雖然都是服務公 衆，卻不適合實際参與政治工作。白天出生者機智，富有行 動力，但欠缺思考性，常常 未經周密計畫及詳加評估利弊，便立即付諸行動,事後才後悔莫及、草率之決定。 晚上出生者则觀察力很強，做事一絲不苟，但領導力弱 ，不善於解説大道理，因此 比較適合領導團隊或從事一些屬於剛毅性質之工作。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','工作拍檔',NULL,NULL,'{工作最佳拍檔} 與鼠： 没有好結果，生意會失敗,或者因破産而結束。 與牛： 牛没有生意頭腦,但他能勤勞工作。 與虎： 虎之運氣不錯,因為鼠雖然有點投機,但總算誠實,否則虎會後悔莫 及。 與兔： 兔之經管手法可笑，特別是當他和鼠一起合作時。 與龍： 理想之合作關係，但一定要由龍來做出决定。 輿蛇： 合作會使人看起來很有趣。 與馬: 不應合作，他們互相僧厭,經常設法傷害對方。 10 盲 派 絕 學 舆羊： 羊會用婪術家之態度對鼠，不知道這種態度 對鼠有没有效力。 舆猴： 可以合作，但鼠一定不要對猴過分崇拜。 舆 難 : 十分冒險,他們不懂得如何做生意。 舆狗： 合作不會愉快，狗雖然現實,但有時太過理想化。 舆猪： 鼠常會對豬施詭計,但金錢方 面，猪之運氣一向都很好。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','合作夥伴',NULL,NULL,'{合作最佳夥伴} 舆鼠： 這是最差的搭配，不會成真正朋友，生意來往會失敗,合作關係會因破 壤而 告結束。相處有時較好，但雙方未必能成為知己，為達到各自之目的，都會 用卑鄙之手段去欺騙和利用對方。 舆牛： 兩者能夠合作，牛雖没生意頭腦,但有 勤勞工作之優點,因此可合作，不過 鼠需要在生意方面多動腦筋。雙方有共同語 言，但不深交，較少來往。 舆虎： 在一定程度上可合作，但鼠須誠實,因鼠總有點投機,虎不把握好，定會後悔 莫及。雙方無友誼可言，因虎之理想主義心態與鼠物質主義者會産生之對立。 舆兔： 合作不能長久，因當兔舆鼠一起合作 時,兔之經管手法是相當可笑，雙方不 能成為朋友，因兔對鼠始終持有極大之偏見。 與龍: 能夠成為事業上之夥伴，都相互信任 。成為好朋友，雙方都傾慕對方之才學。 舆蛇： 別出心裁之合作關係，在外人看來其合作關係根本就不可能現實,不過結局 未必是生意破敗。可成好友，時間與機會經常 鍾情於他們之友誼,彼此開誠 佈公，友誼自然油然而生。 舆馬: 合作是不可能，彼此憎厭，經常設下圈套陷害對方，不成好友，是死對頭, 都崇尚傷害對方，大有水火不能相容之势。 舆羊： 合作帶有相當之幽默色彩，羊用整術家之眼光審視鼠，以非商人之風度應酬 商界，其結果誰也説不清楚。或許能成為朋友，但都很短暫,因志 向情趣各 異,友情終難長存。 舆猴： 可以合作，但鼠在思維上定要自立，因鼠對猴總有點盲目崇拜，其結果往往 令人沮喪。能成好友，但鼠在交往上要多長些心 眼，因猴常會利用鼠。 舆難: 兩者带有相當冒險和盲目性，都不懂得如何經營運作，只能是泛泛之交，社 交應酬而已。 舆狗： 不要合作關係，因現實之狗始終带有濃烈之理想主義色彩，投入生意場,往 往以失敗告終。不能成為好友，崇尚理想主義之狗看不起鼠 認為鼠之志趣性 論命寶 繼 11 格過庸俗，不屑與之來往。 舆猪： 合作關係是成立，在金錢方面，猪之 運氣總是超過他人，鼠可借機獲利，而 猪又無太多損失，合作較愉快。是對開情逸 友，不過外出避樂中，鼠之侵略 性應收斂一下，因為這得不到猪之共鳴。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','愛情',NULL,NULL,'{愛情生活} 討人喜歡,不會因為小事而翻臉,大而化小之個性，對家庭很有責任感，婚後大 都能承擔家庭之重任。戀愛認真，總是希望別人報答自己， 過於刻意，有時反而弄巧成 拙。大多家庭生活美满而幸福，他們對家庭和家人是忠誠者。與人容易相處,除非鼠非 常喜歡之人，不會有所表示。其珍惜與親朋好友之 關係，並對之有著深深之依戀。 内心感情十分豐富，對喜歡、愛慕之人十分仁慈寬容，如舆戀人發生爭吵時,禮 讓三分，能獲異性之喜愛及優勝之地位；但很難一帆風順,因對方不易付出真情，防婚 變。只剩一片癡想，此心態令以前所有之努力付之東流。 女性： 雖很實際,但又是理想主義者，總愛做白日夢,追求虚無缥缈之 愛希望在人 之心目中永遠是優秀情人，包括外表及内在。較任性，常要求 舆戀人自由平 等。對戀人懷著敬佩之心， 一旦發現不是理想中那麽高明時,會失去信心。 對戀人之要求很高，是很完美主義者能獲得您之芳心之男性， 一定都是 很有 才幹之人，她不僅要求對方之長相，就是許多世俗條件，也得合符她之高標 準。 男性： 待人親切、和諧,心胸廣闊,且擁有廣博之知識。在戀愛時, 温和爾雅、體 貼備至、誠懇、樸實。婚後在家庭生活是近 乎完美之丈夫，雖崇尚理想，但 為家庭會面對現實,讓自己努力當盡責之丈夫，慈祥之父親。您誠懇、模 實,但不能抵抗女性之誘惑，令人懷疑鼠之人 格。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','本命特性','婚姻',NULL,NULL,'{婚姻家庭} 黑鼠黄牛雨相合，二家成親無錯覺；夫妻恩愛 同到老，好似鴛鴦不分隔。 鼠蛇相交錯中錯， 一個心凶一個恶；白把青春浪費過, 若不相讓命難和。 皆知性而有魄力，鼠女才華横溢，為人極富同情心，愛好整潔,在家庭中是一個端 莊秀麗、媚熟文静、聰明能幹,會把家庭管理得很好之賢妻良 母。鼠男多半勤勉多學 富有廣博知識,且很有進取心。 判断力很强，幻想力豐富，偶爾也會有創造性之表現,但可惜在感情上很難自我 控制，不自覺中而變成一個破壤者，或打撃他人，在愛 情上那怕所愛之人意有所屬,但 依然是大方之態度，在婚姻問题上很慎重，你常選個性相投 之異性作為配偶。很受人 喜愛、細心、體貼、温柔，對愛情充滿浪漫之憧憬，有強烈之好奇心，態 愛中恰你之快 集，安慰。婚後會把家庭管理的很好， 一切以家庭為重。 肖鼠之婚姻對象； 肖鼠之戀愛對象； 肖鼠之不合對象； 鼠女——牛、免、難、豬。 鼠女——龍、蛇、羊。 鼠女——馬、蛇。 鼠男——免、龍、猴、點。 鼠男——虎、免、蛇、羊。 鼠男——蛇、狗、馬、羊。 鼠男婚配 配鼠女：最佳之選擇,非常完美之结合，兩人在一起定能産生甜蜜之爱情，能真正幸 福快樂地生活，領略到柔情似水之温馨感受。 配牛女：完美之配對,比較理想之婚姻，牛之愛和忠心給鼠很大安慰，使鼠之激情和 浪漫心程有依記舆基礎。而牛並不會因為鼠者不 拘小節之個性而影響其背叛 兩者間之相知，所以没有因個性衝突之問題,將會相親相愛，同享平静和諧 之婚姻生活，六合之相，易受牛之吸引，您會發現牛是强者 可依靠，且欣賞 牛所奉獻之忠誠,是上等之婚姻。 配虎女：不太容易，難為夫妻，虎對浪漫之追求及一些不太現實之 想法讓鼠很不快。 配兔女：感情不太融洽，不太適合結為夫妻，因 兔有意無意會作出對不住鼠之事情， 而鼠未必會忍氯吞聲，這讓鼠感到失望、沮喪。此 結合會存在很多問題,仁 慈之兔也許會把鼠因艱苦勞動换來之積蓄揮霍 清光，尤其兔女無法控制感情 生活，很有可能會做出對不起丈夫之事情，且子卯相刑，此乃下等婚配。 配龍女：相處得和諧,比較理想之結合，鼠最善解人意，並懂得如何尊重他人，能夠 满足龍之虚榮心。龍非常欣賞鼠之機警和寬容。並且 以鼠之才幹,配合龍之 活躍,在事業上將有很好之發展。從命格上，子辰三合，相處得很和諧,兩 者吉祥百年，恩愛同心， 一生好合是不用擔心。 配蛇女：能結合，但不太和諧。鼠之善解人意和體貼使蛇生活十分愉快，但蛇還有可能 不满足，這讓鼠非常煩惱。因為兩個没有理性之人很難共同相處在一起，尤其 是蛇人有向外發展感情(婚外戀)之可能，生活上各懷心機,分手之幾率很 大，而鼠還會發現機警之蛇也具魅力，兩者退一步，可 能會結成適當之聯盟。 配馬女：非常不適合，最好是另擇良偶，两人彼此都比較衝動 、盲目，且不能相互容 忍。從命理上，子午正冲，屬下下之格局。馬對酷愛拉 幫結派之鼠會顯得十 分孤立，並且使人捉摸不定。因此最忌與馬人結合。 論 命 寶 镭 13 配羊女： 带有功利性之婚姻，羊愛鼠之財富，仁慈之羊也許會把鼠用艱苦勞動换來之 積蓄大肆揮霍掉，且要想盡一切辦法控制鼠。所以即便勉强在一起，相信也 不會有很好之結局。依地支合破，子未相害，『鼠羊相逢一旦休」 與羊結合 存在很多問题，仁慈之羊也會把鼠人用艱苦換來之積蓄大肆揮霍，因此 屬下 等婚配。 配猴女：比較美滿之婚姻，猴之精明讓鼠很不舒服，猴或許會 欺騙鼠，暫時會引起鼠 之誤解和傷心，但最終會得到鼠之諒解。因權力所傾倒，鼠會迷戀 猴，很欣 賞聪明之猴子辦事方式；猴會非常高興地按鼠之旨意去説話辦事。依地支格 局，申子辰為三合，屬上等之婚配，美好之良緣。 配難女：相處比較和諾,難之很多優點足以使鼠容忍她揮霍無度之生活。且生活有默 契，但酷愛幻想之難會無休止地激怒追求實際之鼠，此結合帶有危 險性，甚 至會不幸福。 配狗女：非常有趣之婚姻，狗之煩悶時由於鼠經常呆在家禮。 如果鼠能經常外出，狗 會很自由和開心。最終還是能和睦相處。 配豬女： 非常美满幸福之婚姻，猪之財運不錯,可以找到許多錢,而鼠比較精明能 幹,彼此互補,故是天造地設之一對好姻緣。但鼠不能太放肆，否則猪也會 採取對抗措施。造成矛盾。猪性格開朗樂天，能與鼠和 諧相處,彼此分享快 集和憂愁，所以，相信都能實現終身幸福、美满之願望。 鼠女婚配 配鼠男：很理想之婚姻，他們纏綿之愛情令他人羨慕不已。因 兩者性格和運势大同小 異,俩鼠相配，相當不錯之選擇,能領略到柔情似水之 溫馨感受。 配牛男：很一般之結合，但婚姻、愛情都不會有有太大之波折 ，會有平静而和諧之婚 姻生活。雖比較平淡，但也許是真實之生活能維持長久。乃是六合之格局， 鼠易受牛之吸引力，且發現牛是強者，可以依靠 ，欣賞牛之所奉獻之忠誠。 配虎男：如鼠能容納虎之冒險行經,他們便不會為愛情而煩惱,定會白頭借老。在一 起也能達到和睦相處之目的。 配兔男：結合不會太愉快，因兔喜歡交際應酬，常和朋友在一 起，往往會忽略庭和妻 子，這讓鼠非常不滿。鼠之地位不穩固，她嚮往純潔之愛情 。因而雙方易起 爭端。 配龍男：非常幸福之家庭，鼠之奉獻精神成就了龍的事業,龍因此非常感激她。申子 展三合，故相處得很和諧。鼠能奉承、滿足龍之虚榮心，並且以鼠之才幹, 14 盲派經 學 配合龍之活躍,在事業上將有很好之發展。兩者吉安百年 ，恩愛同心， 一生 好合是不用擔心。 配蛇男：非常不幸之婚姻，因蛇經常會欺騙鼠，而她之輕信常 造成對自己之傷害。在 戀愛中鼠常常為感情衝昏頭腦。兩人都是没有理性，很難相處在一起，尤其 是蛇具有向外發展感情之可能，生活上各懷心機,分手之機率很 大。但鼠會 發現機警之蛇具有魅力，可能舆蛇結成適當 之聯盟。 配馬男：婚姻不太美滿，彼此不是很信任，常 鬧彆扭，有分歧。子舆馬相冲，馬對鼠 之酷愛拉幫結派會顯得十分孤立，且使人捉摸不定。因此，最忌舆馬結合， 是下下等婚配。 配羊男：很不理想之婚姻，因彼此想利用對方， 故結局多是不歡而散。且子未相害， 舆羊結合存在很多問題，仁慈之羊也許會把鼠多年用 辛苦勞動换來之積蓄大 肆揮霍，『羊鼠相逢一旦休』,且羊總想主宰鼠之生活，所以即使勉强 在一 起，也難持久。 配猴男：非常理想之婚姻，甜蜜之愛情，幸福之婚姻將伴隨一生。由於為權力所傾 倒，鼠將會迷戀猴子，很讀賞聰明之猴辦事之方式；而猴會非常高興地 按鼠 之旨意去説話、做事。此乃上等之婚配，美好之良緣,相信都能實 現終身幸 福之願望。 配難男：非常不和諧之婚姻，夫妻吵架常發生，家庭永無寜日，甚至同床異萝。生活 極為不協調,兩者結合是不幸福，酷愛幻想之難會無休止地激怒 追求實際之 鼠。 配狗男：能夠達到和睦相處,很理想之一對,鼠對狗之溫柔，能使狗之理想世界更接 近現實。兩者在一起也能達到和睦相處之生 活目的。 配猪男：比較美滿之婚姻，鼠有時太放肆，這會對猪造成傷害，故鼠收斂自己。不能 太放肆，否則，猪也會採取抵抗措施，造成矛盾。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('子','鼠','精批榮祿','生月',NULL,NULL,'{生月運势} 男 ： 正(寅)月生帶鐵掃、孤辰；二(卯)月生破月；四(已)月生重婚；八 (酉)月生帶桃花；十(亥)月生帶亡神。 女 ： 五(午)月生再嫁；六(未)月生破 月；八(酉)月生帶桃花；九(戌)月 生守寡；十二(亥)月上帶鐵掃。 正月： 寅月生人——為人忠厚、富有俠義心、仁德待人、同情心深、犧牲自己，成 人之美。但有神經質而重感情，利官近貴,可富資 增榮。然大事小成，凡事 仔細，若不失機,能招四方財。幼年平常，中年運開, 晚年榮富，無刑剋夫 之命。 享受自來之食，祖業根基較深：能得上輩蔭庇。 父母兄弟夫妻都很寵愛鼠 論 命 寶 篮 17 二月： 18 人， 一生過得是不劳而食，豐衣足食之生活。新春之時,無論窮富，家家均 是葷，而鼠嗅必喜，口福不輕,但油葷太多必 自强心高、自以為是、不聽勸 解，甚至終年好吃懒做、量頭暈腦。 年輕時運势平常，到35嵗之後運势會逐漸開朗，步上順境。很熱心且努力不 懈，絕對不會令人生厭。 有臨危不亂之大將風範,遭遇困難時便會激發您堅 朝之潛力，冷静而快速地 解决問题，因受前面亥年之影響很大，有自信過高，固執己見之缺點。應在 基礎部門腳踏實地地積累工作經驗為以後之發展建立陣地。 適從事造船技師、建築技師、醫師之工作。女性思想開放，有社交家之胸 襟，很理智，不會輕易受外來誘惑而被人控制。因 此在選擇異性朋友方面， 如果是男性，就較適合 丑 年十月出生或子年三月出生，能確實理家的 賢慧女 性。而子年一月出生的女性，則較適合與 丑 年一月出生的男性結 合，因為 丑 年一月出生的男性具有不很在意事情的開朗胸襟，正好與子年一月出 生的女 性互補。 老年容易患癡呆症、多動症，雖長夀而不得好，所以年輕時應常常活動腦 筋，多做運動。 卯月生人——平生善良自有持，勞碌增榮盛有餘;錢財家業中年好，貴人提 拔上雲梯。 為人誠實。出言無毒，善作陰德，六親少靠，諸事謙尊，成功如登梯，貪急 則失敗,切記随機行事，方萬事安然。初年辛苦，中年發達 ,四十興榮後, 可終年利路亨通，乃虎假半真之命。 在坎坷中掘起，幸福渡過大半生，氯質文雅，才華 出衆，文章能蓋過很多 人，但膽小怕事， 一生難成大事，祖輩幫助很大，但遺産卻不豐厚，兄弟姐 妹能和睦相處,互相幫助。 在事業上，只能以文章獲取功名，求得一官半職,難掌 大印，多任文秘之類 之職務,早年難以幹得自己稱心如意之工作，每天辛勤，奮力學習,在千辛 萬苦之後終於能在文化種類中見得一個好去處。 缘分方面，男性因喜歡忠真、嫻淑，能完全把心思投注在繁雜家務中之女 性，娶羊年九月生女匹配，他十分重視妻子。女 性；多具光澤滋潤之肌膚 能充分吸引男性，嫁猴年七月生男結婚。 您小時候幾乎没缺少過零用錢,因為深受長輩疼愛 之您在大人面前最會扮乖 盲派絕 學 小孩，就算付出想要什麽東西也會讓家長没法拒絕您。您對錢一向管理得十 分謹慎，就算是您很好之朋友，想找您借錢,您也會婉轉地拒絕,將 來之您 適合從事金融行業及管理工作。 老年容易患癡呆症、多動症，雖長夀而不得好，所以年輕時應常 常活動腦 筋，多做運動。 三月： 辰月生人 誌氯不凡，内心强固。交際巧妙、腦智清 晰、寬宏大量，事多 忍耐、堅持奮鬥,莫要錯失良機。 應修身謹慎，有重色情破前程，為色情害良緣之虞 。卅嵗前逢盛運,財來財 去，有虚無實;四十葳後自安然，凡事順遂，不可焦急，福祿永生。 一生膽 小怕事，孤僻寂寞地度過一生，心腸極為軟弱、善良、愛掉眼淚、有厭世嫉 俗之心，把世間看得一團灰暗，有百事成空感。 一生常見喪門,到處碰見晦氣，雖有酒肉之食禄，無奈時有流淚痛心之事， 凡事慎重，總是先掂量自己之能力，才敢行 動,因此對於將來之預测，不致 有重大之損失或偏失，總是腳踏實地， 一步一步地向前遵進。 雖表面上看起來好像是行動積極之人，但實際上内心充滿疑慮,喜歡思索。 故不善於合作，不適在集體中工作，喜歡獨立生活，在自己獨立之世界中工 作，會感到無比之充實。 一旦別人找您辦事，則不知怎様去拒絕。因為 這種 弱點,所以有很多朋友，但大多數是酒肉朋友 ，舆您交往之目的是為了獲得 好處。對這類人應慎防之，有時自己順遂之運勢，會被這類人所破壤。在經 濟上尚有波動,須早做準備。 缘分：男性不善處理情感之事，故娶馬年五月或虎年九月生女。女性；嫁不 是長子男性，猴年三月、已年三月生男。此外鼠男女在婚時與對方交换婚前 健康診斷書,尤其性病方面之檢驗,以免日後追悔莫及。 老年容易患癡呆症、多動症，雖長夀而不得好，所以年輕時應常 常活動腦 筋，多做運動。 四月： 已月生人——廣交朋友，多才巧智，學兿能成功，欲望過大，心性難定，宜 不懈奮鬥,終得發達。侠義心強，肯犧牲自己 ，敗强助弱，後逢貴提拔。聲 揚名震，三十七葳後發展，為頭目之人。 一生衣禄平淡，奔波勞碌，乏祖業幫助和遺産，兄弟姐妹情缘較薄，難得親 人幫持，在外又無貴人扶助。無法發展大之事業,時常受歧視、戲弄，在家 程，多無賢慧伴侶，且多遭災禍,如出生日、時辰好者可改善此命運。 論命寶 豔 1 9 五月： 六月： 20 純樸、快樂、對人親切，人見人愛,抱負很大，總想出人頭地，當高級領導 很適合。假如只是空想而不努力，當然是事與願違。幸有春風化雨，終得良 夫賢妻扶助，衆人仰視,一生所遇機會甚多，中年出頭。 適從事時常處理資料之公務員或數學研究之職,若開辦企業可發展前 途。 缘分：男性適於個性開朗，善交際之兔年八月生女。雖然女性很嚮往純潔之 愛情，但常會自 我可制，而接受雙親為他所選擇之伴侶。適與狗年十二月生 男能把理想寄託在家庭上之男性。 您對錢一向管理得十分謹慎，就算是您很好之朋友，想找您借錢,您也會婉 轉地拒絕,將來之您適合從事金融行業及管理工作。 女性娟秀，輪廓鮮明，發質黑亮；具有忠於愛情之勇氣,和聽從父母之命之 自製心。 午月生人——為人善良，性情温和伶俐，有權有勢，行而正道，自能成功， 恐對事虎頭蛇尾，無忍耐性，遇良機不能得，離祖成家，夫婦半途，婚遲為 吉。卅一至卅五葳後,方能大得利益。 鼠人艱苦奮鬥,幸福榮耀過一生，上無祖業,且乏父母支援。 一生全靠自己 聰明靈活之頭腦和堅持不懈之鬥志，以及勤勞之雙手去挣來衣食。在外有貴 人扶持，事業能順利而又艱難之向前發展，財源會滾滾而來,到中年後,家 中錢財堆積如山，成為一方巨富，受到思人敬仰，萬人崇拜。 東走西奔、機靈應變,勤能忘食，不失良機,能成富貴,能成大事， 一生不 畏艱辛不怕凄凉，可獨立成家。因一心想要出人頭地，所以有時做些自己能 力不及之事情，若事成，則能成萬衆崇拜，成為人之模範,老來自福，始終 無大難。 不善修飾、個性模素、開朗、而又親切、待人大方，易得人好感。雖具有將 來成就一番事業之雄心壯志，但須付出巨大之努力，以免理想變幻想。 女性愛乾淨、甚至有潔癖，在獨身時代非常活躍,常喜歡成為大衆屬目之焦 點,屬於十分容易墜入情網之人，但很快就會恢復理智仔细分析對方。婚後 變成視野狭窄、眼禮只有丈夫、孩子之典型之賢妻良母。 適做都市計劃關係學者、航空管制官、從事思想、整術者之工作。 緣分：男性因具有較好之控制物件能力，適娶牛年八月生女；女性適與龍年 九月或狗年六月、寅年六月，能領導他人之男性結合。 未月生人——為人遠達，心巧伶俐，思慮緻密，整術多能。 盲 派 絕 學 具努力有堅定信心者，終為達發達。若貪小 利失大財,勿剛複失和平，重色 必破家庭，白手成家難得祖業,初限難為,中年平順，未運富貴。 一生艱難困境中崛起，出人頭地之度過此生，祖業根 基淺薄，乏遺産可繼。 六親無靠，事業全靠自立，在事業上有貴人支援，但自己身體欠佳，心有餘 而力不足，性格剛毅，意志頑强，能在困境、逆運反 彈,終於能在事業上獲 得成功。 熱氯陰陽,光明樂道、遍地皆春，但具有温 和，容易交往，内在卻很堅强之 特點。即使當您滿臉笑容時,内心也不會真正之喜悦 ，很少打開心扉與人真 正交往。因受烈日影響,身遭其疾，可能缺水乾渴，宜居於江河湖海之畔， 多尋水源， 一生出頭人上。 行動敏捷，個性開朗親切，具有幽默感。常 有誇張之行為舉止逗得身邊之人 開懷大笑。愛出風頭,為了成為矚目之人，有時會做些 自己力所不及之事 情。且喜歡炫耀財富，這種虚榮、華而不實之個性，常使其失去良好姻緣。 在工作中，易舆上司發生衝突，時常有轉行之念頭。但在30葳之前不宜更换 職業,可選擇導避、運輸公司、化學公司之工作。 緣分：男女很注重精神生活之满足，有選擇和自己個性完全不同類型之傾 向。男娶行為慎重、樸素，猴年二月生女；女性應和擁有比自己更模素之人 生觀,才是獲得幸福之快捷方式的虎年二月生男。 七月： 申月生人——心地慈善，作事仔細，為人親切，外剛内 柔，意志堅強，作事 始終。少年辛苦，初限破敗,為子女煩惱,小心陰人，中年後開泰，晚年家 庭圆滿，財源大進。 衣食豐富，幸福渡過一生，祖業根基深厚，遺産豐富，父母幫助也大，兄弟 姐妹夫妻子孫能和睦相處,互相支援幫助，不须勞碌 衣食也很豐富。心胸寬 廣大度， 一生有貴人扶持，事業也會成功，且無 大凶大難,是人間福人。 五榖豐登、不需勞碌。須防小人陷害，不可糊塗、接物待人、寬容大方，雖 有失敗、但天賜之祿，衆糧送倉,不怕天災人禍,决不求乞於他人。自身年 月支相生，為金生水， 一生衣食無憂，自