INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流年運程',NULL,'卯','逢兔年','猪逢兔年 命逢『五鬼、『技頭』、『將星』、金匱」、『官符』、『三台」 、 『飛廉』。 其年食神得生，則運轉為財,財充裕，運行正財，轉禍為福，財源廣進。在夏至之 間有可能加官進爵，葳末時防官鬼之人。免遭牢訟，免遭勞累害己，凶時 過後大吉，須 廣結善緣,三山進拜，有利勿害。 今年有「金匮」、『三台」、『將星』三大吉星飛臨, 均主當權、當势、當財,其 中『金置』為財源特級星，主進財增地及事業大進 ;『三台」主科甲功名，增進名氣、 事業、升遷;而「將星。是能得到優秀之部下 相助大業,可見你今年可全力進軍,再陷 數城，收復失地。 有凶星「官符』、『五鬼。,代表是非官符，有不利本 身之檔及官認是非，故要搞 好人際關係，小心暗中利箭，以免受損,而令你防不勝防。 九五年、七一年生人兔年行正「曜曜』,而四七年、七一年生人命入『計都宮」, 均代表會極易捲入凶運麻煩,幸好整體運势向上，而這些小麻煩只是一種磨煉,不足為 患。只要你有「處變不驚。之心理，兔年須可過關。五九年生人则財官兩旺 ，但勿貪酒 色，必誤前程。 大利進财，九五年、七一年生人，兔年財運最好，其次為八三年、四七年生人，今 年都可擴展業務,生於八三年者兔年貴人極多，升遷機會極大。兔年你大利 擴展之月份 為農唇二月、五月、七月，下半年有退氣之象。 今年是『儲財年』,『人氯急升年」,一切有開名氯、知名度、人際開係之事業缘 分很好；亦是「處變不驚年。,會有官讼是非，因此，錘而走 險之猪人，兔年就容易受 136 盲派經 學 『官符』、『飛符。、五鬼』此三凶星所害。故豬人今年須努力工作，增加進修、减 少暴躁，以免一個「亂:字，而壤了大事。在適當時候， 還是明退實進,玩弄一點虚實 為好。','大吉',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流年運程',NULL,'辰','逢龍年','豬逢龍年 命逢『月德」、『小耗』、『紅鶯』、『女犯命星』、『死符』、『板 鞍。、『卒暴』。 其年運行正官，必得主權,紅驚喜臨,必得良緣，出馬遠走他鄉,凡事有樂無憂, 赫赫有威、勃勃生氯。然有小病破財，葳逢月德，肆無忌憚,而名旺貴 重，財耗酒色， 人喜奉承，愛虚榮,喜豪華、慷慨好施，只怕命存財 空，僅為衣食而已。 踏入龍年，你欲再起風雲,還是時不與我，看來猪人在未來兩年，還是在平 淡中穩 步上揚,要到馬年，才有運披甲上陣。 工作不是生活之全部。你這两年，是最宜進修及拓展身心之年運。但切勿在龍年急 步進軍,或將自己放在第一線,這只會令你急躁難耐，危機頓生， 一去不可收拾。 因為在龍年，你唯有『月德」吉星來助旺，此星是德行及名氯之增加，是有名無 利，而猪人龍年之一級吉星『紅驚」,可見未婚龍年之首要 任務,是投入感情世界，找 尋一個理想伴侣，這是你龍年之整體戰略。 你很重視配偶之加特力，雖然你自己不承認,今年吉星不足 ，宜舆六合虎肖、三 合羊肖、兔肖多合作，兼取他們龍年運势之吉星，包括 有「太陽』、『福德』、「福 星』、『天德』四大吉星來旺。幸好今年你之當年星均是吉祥之辰，可望你今 年笑口常 開,在人生領域上享受精神世界之豐足。 因此，是事業、財運上，最旺之月份為農唇六月，最恶劣之月份是農層七月，旅避 以農唇四月、七月最好。五九年生人運勢極佳，享受愛情及天倫之樂。而 失婚之五九年 猪人可有第二春之兆，如晚來追子追女，龍年是最好機會。四七年生人小心身體健康， 肺部、呼吸功能小心，但財運很好。九五年猪女則桃花旺盛猪男有名氣之 功；七一年豬 人小心親屬之影響,八三年猪人留意太肥所带來之健康後遗症。 龍年你應以守為攻在人際關係上及社會生活上多建立基礎 ,但在事業及投資項目 上，不要太拼，否則泥足深陷，苦足兩年。','大吉',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流年運程',NULL,'巳','逢蛇年','猪逢蛇年 命逢『成破』、『大耗』、『解 馬』、『破碎』、『披頭」。 其年運走偏財，驛馬奔他鄉,事業多思轉向，投機取巧，定有所得。發如猛虎，凡 炒股、搖奬、買彩、投機取巧，雖然終不空虚，定有所獲,但之後須防樂極生悲，大耗 論命寶 證 137 其射，披麻戴孝當見。行事宜小心謹慎。 運走偏財，會有很多幸運之生財機會。凡有關投機之生意，佛体之抽奬，都 有很多 獲利之機會。但可惜大耗及葳破當頭,恐怕聚財不 牢，失財於後防不覺之地，結果一場 風光，半夕春夢。 財運頗佳，尤其是農唇二月、五月，會有很多發財之機 會。但要同時小心四月、六 月都會使猪人無缘無故地失去一筆钜款，所以有孤注 一掷性格之豬人，要分外留意。事 業運是奔波勞碌，計劃如浮光掠影，這是一個充滿希望又充满失望之年。 今年恐有親属遇毒劫之災,而猪人如果過份投機,雖然蛇年見利，而且處處見傥 体，但恐會加强猪人之雄心，結果一子錯而满盤皆输 ，這是你特别小心之大起大落所带 來之難以翻身大危機。','大凶',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流年運程',NULL,'午','逢馬年','猪逢馬年 命逢「紫微」、『龍德」、”朱雀」、『八座、解神、地解!、『暴 敗」、『天厄』。 其年正行財運,經管遍四海，謀利達三江。財豐利厚，雖有天難傷害，尚有龍德紫 薇兩星保駕,退難有救。但須亥水剋午火，務必居安思危，否則口舌四起，朝東幕西 求此而失彼，生意無聊，來去空空，損一年好運,而嗟歉 人生。 平平穩穩，大有餘慶,風光自得，可説是一個中庸年。而一切之要遷，都封你有百 利而無一害。因此，應好好享受，過一個平順良慰之太平年。 九五年、四七年，五九年豬人，馬年都有變化，應之在 搬遷、工作、感情上，但都 是愈變愈好，故你不必怕變,可顺應變幻而自得其集。 因「地解。化吉， 一切小人之暗箭加害，都對你無所用其技，加上「紫微』星照， 諸事吉利如願,你可發威，但猪人極易因鋒芒太露 而失思和，較為孤意獨行，故大思性 之事業,在馬年較不易開展。其中以農層五月、十一月之事業運最佳。 特別一提是猪人在這平順之年，特別留意下腹部之疾病， 而猪男猪女馬年游泳，要 分外小心，不可強意猛進而損害健康。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流年運程',NULL,'未','逢羊年','豬逢羊年 命逢『白虎!、『天哭!、『華盖」、『大耗』、”天殺、威殺』 、『黄 幡!、『飛廉」 · 其年運走正官，流年有顺，造就良機,文思尤進,晋级得時,必得其權;若能多做 少言， 一年聲名平安上進,但宜謹慎，少奔他鄉,不謀新業或另調他職不利。 且流年有白虎破財,官興財失，大樹稍動,則天災人福，故要三思而後行。工作進 138 盲派經 學 展諸多阻滯，而且會有不少人事紛爭,可致工作壓力沈重，甚至停滯 不前，除了保持自 信心努力不懈之外，遭需及早找出陷没在背後作祟之小人。 羊年工作進展多阻滯之月份是農層二、三、四、六、七、 十月，必须保持警惕。農 層正、五、八、十一、十二月運勢較佳，應好好把握良機奮發向上。 運勢較佳，心想事成，造就有機,香級得時,可謂一個好 時年。若從事文化事葉或 動腦行業,羊年會有很大之噩機,均會為豬人招 來極大之財利。加上年走正官，豬人會 掌權力，但小耗難免，消費較大，遇避有利，好好享受物質生活。 威情生活不俗，但不要太滥情，否则會招來極多麻填是非。宜 多舆配偶享受羅曼蒂 克之生活，不僅會豐盛自己之精神世界，而且財官兩美，人形光彩。 今年吉運加強，勢如破竹、所向披靡，最佳之月份為農層二 月、四月、九月、十二 月。但你特別小心農層五月、六月、七月，會無故生煩,失服和睦，你適宜減少急躁猛 進之性格，否則會招致孤軍作戰,非上乘之道。','大凶',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流年運程',NULL,'申','逢猴年','猪逢猴年 命逢「福德』、捲舌』、天德」、『劫殺』、貴神』、『技麻! 、 「六害」`『勾紋!、『福星」。 其年運走偏印，葳動可見孝事，披麻哭聲當見,大則病傷命亡，小則有是非口舌發 生，凡事需謹慎行事，深思熟慮,可免其一。 財利欠足，生意平中有折。只因瞻前願後,不敢放膽而為之。葳初吉少兇多，萬事 不宜，後半年運势平中有升，嵗末也有小收穫。 工作會有諸多阻滯，工作壓力大，不宜推行新方案，也 不宜有其他新措施，否則非 但徒勞無功，還會授人以柄。切勿舆上司發生衝突，否則遭 患無窮。 全年工作最多阻滯之月份，是農層正、三、四、六月、十二 月，在這期間,必须 特別提高警惕；除了要努力工作之外，還要注意人際關係。工作較锡順之月份，是農層 二 、五 、十月，應好好把握。 通程不俗，有極好之權威，人缘也大為拓展，從事各 行各業,都應擴張及升遷,從 事金錢角度，你確然在猴年有不俗之表現,但柳暗花明之處,邵為你暗藏很多危機。 今年是一個劳心勞力之年，雖然多勞多得，但心意難平，且口舌是非極多，都會令 你不勝其煩。此種外表風光，内裏憂患之情形，正好描寫你今年之運勢重點所在。 你先天傲氣較重，孤意獨行，故易失衆和，在推動事業 過程中，人事糾纷難免。今 年之劳心糾纏，多來自合夥人及家庭，猪人務必小心。 猪人切記要建立好儲蓄計割，並增加靈修，使自己憑宗教或哲學來提昇自己之思想 靜 命 寶 罐 139 境界，超越自我。 猪逢羅年 命逢「天狗」、『吊客』、天殺、處殺』、「八座、解神、天解』、 「女犯河魁』、”的殺」、「破碎』、四獄! 酉金生持亥水，本是大旺，但因酉亥相刑，反有動温不安之事。財庫有破，利 路欠 通，經管謀劃多半不成，防小人作阻，渐生詞讼之禍,遭牢獄之災。 本年運在名權不在利，求財不利，但當官有運,應見機行事，多結交貴人，若得天 時、地利、人和定能如願以償。 事業發展頗為楊順,可收事半功倍之效。而且又會有貴人相助，更是如虎添翼；但 因有貫索』凶星出現,故此凡事切勿操之過急，以免失足而一敗塗地，事業發展較為 暢順之月份，是農層正、六、九、十一月，應積極進取，好好把握良 機;農層三、四、 八 、十月則必须提高警惕，小心處理業務。 運势平淡中生姿，屬中成之局，仿似剛發芽之幼苗，要再生衡下去，雨水陽光又不 足，那細芽要萎縮又不死，你今年顺中見逆，逆中見順,是一個矛盾而又妙趣横生之流 年。 遇到此種怪現象，主要吉星力氣不足，但凶星制 壓,處處令你墜入反復變幻之是非 中，因此今年最好安於本位，做一個平常人， 一切照舊，以不變應萬變。 事業運行正印，只宜正財收入，不利較大之權力，而當老板者，難年事務也趣向穩 定而且人事烦惱,會較去年為少。事業之發展依然得個『守。字。 不宜出外太多，以静制動為好，尤以落後地區或危险高處勿近，否則會容易發生意 外，切記切記!今年夏季游泳，也必須與友人同往，不可單人赴會。 你今年有二防： 一防盗贼，破財為喜，傷人事大；二防官非，口舌是非，範文件及 乎論會導致官非。 今年移民運極佳，是一個大好之移民年。 你在此數年依然以反復運為主，難年是反復中見吉星為主，只不過吉運不能長久， 也欠缺穩定性及長遠性，令你難以安心下來。今年是改進自我之年，因此孤意獨行，失 衆調和之作風要改進一下。 雖年是「忍耐年』,對你而言，此年要使你戒急戒勇，要學懂觀整盤格局，因此今 年是一個學習年，亦是修心年。 猪人自我心太強，難年忌孤軍作戰、廣結善缘是首要任務。 140 盲 派 絕 學','凶',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流年運程',NULL,'戌','逢狗年','猪逢狗年 命逢「病符」、「陌越」、天喜』、寡宿。、『嵗殺」、”浮沉』。 其年運走七煞，本可運起嵗中，只因七煞不吉，時機極難把握，幸而天喜降臨,噩 蘿轉眼大醒，必有一收穫，不枉一年辛苦，吃苦耐勞是您求財之 唯一途徑,雖無大財, 但收裕不少，應樹立信心和勇氟，千萬不能懒散。 『宜做打工仔，不做事頭人。」身為老闘者會四面楚歌，刺 激增多， 一直深藏之缺 點都會顯現出來。受薪者反而輕快得多，但要求大幅 度加薪則較難成功。財運普通只求 平穩過渡，難求大發特發,只不過年尾變動較多。 猪人孤意獨行，認真而固執,且心難藏事，直率過人。私心難免，容易氣馁喪志。 在當旺之年，這些性格會成為成功之優點,但一到運滯之年，這些優點變成極端，就成 了失敗之因由： 今年是一個忍耐年，忍得就忍。因有葳煞凶星加臨,不利「 七』數,主諸事不成， 而且破財多雙,對於五九年生人要以守為攻，時運失調,是最差之猪 人，而生於四七年 者，運道較佳，其次為九五年、七一年生人，狗年大 運欠佳，但小運不俗，大利財運; 八三年生人狗年較宜增加運動量，要有充足之睡眠，小心疾病舆爭認，宜配金器化煞招 三合只要保持中庸，可望開開心心過此年。 狗年是『宜為受薪者，不作事頭人」,為老板者狗年會四面楚歌，刺激增加， 一 直深藏之缺點都會顯現出來,多會勞而不獲。受薪 者反而輕快得多，除了要求大幅度加 薪，勢必失敗外，要保持原狀，势必成功。因此，今年財運普通。只求平穩過渡，難求 大發特發。只不過狗年年尾變動較多。 狗年是檢討年，你自傲之性格狗年受到正面之衝撃，你應多加反省， 覺悟，並應將 目前之處境加以調整，秘訣是「化整為零」,將 多餘之東西取缔，集中兵力和財力，嚴 陣以待，隨時参戰: 今年是平衡年，猪人之缺點是太集中於事業,忽略了生活情趣。應將生活 擴闊,除 了工作外，應兼顧家庭、娛樂、運動。狗年應增加運動時間,並拔出時間進修。你宜享 受大自然之自由空氯，將自己解脫出來。','凶',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流年運程',NULL,'亥','逢豬年','豬逢猪年 命逢『太成』、『血刃」、『地煞」、『自 刑』、『伏屍』、 八座、解 神、天解』、『指背」、『浮沉」 · 其年比局之運,年犯太葳，交友不利，小人搗亂,事業不穩,謀劃不順,凡事平 常，只宜受不宜攻，待時機而動,身體需好好養護,本命使之然，需備朱砂在 身，趣吉 避凶： 盖 命 寶 罐 141 求財不利，切忌投資大額生意， 一切以保守、穩健為宜。偶酮會見膿血 之災,很難 心想事成，可以三餐衣食，心寬體胖。 猪人活潑機智，可惜孤意獨行而失衆和，適宜做合作性較低之工 作，否則是非招 惹，暗箭難平，且猪人自私心强， 一到這些太葳年，稍有變動,猪人很容易會失去分 寸。 今年有『天解』、『八座」二大吉星飛臨,此二星匯合之力量，以化 災為主，不以 招吉為任，因此，今年不宜進取，只宜退守，加上太嵗來犯，如八字中『亥」 為用神， 反主吉度之事，但如非用神，猪年太嵗會較為順逆不順，因此，如能以處變不驚之態度 來面對,視猪年為挑戰年，不失為開敵智慧之『開殿年。。 事業、財運上，九五年、四七年、七一年生人之太藏主變 好，但五九年猪女，猪女 必主大變，財運亦會較為反復。整體而論,今年會有劍鋒』、『浮沉」、『指背」三 大凶星齊駕,主不利偏門行業,「劍鋒』只利正行權威，大利警界猪人。今年思慮會心 大心纽，宜與肖子、肖牛之人合作，會平衡這種心魔，且今年亥亥自刑，會過 份自我， 對於投資及作重大決定，必會因過份自信而招損失。除鼠、牛人外，多聽取羊人、兔人 之寶貴意見及忠告，亦會開竅。最佳財運月份為農層二月、五月、六月。 今年是『變化年」,變中求勝為大方向，因此，不懼「雙』,而喜變」 ·要迫使 自己改換一下環境，以求再闖高峰。今年亦是忘我年」, 多聽他人意見,不能剛愎自 用，以忍』為先，否則會被「指背星。之小人氣壤。 {','平',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'寅','正月','逢正月： 運势反復，會出現諸多阻滞，故宜保持低調,不可輕舉妄動, 尤其是不可招 搖樹敵。工作方面會出現諸多掣肘，難展所能，應切記針鋒相對,宜以静待 變，緩以圖之。財運平平，感情易生變化，宜真誠待人，小 心維繫。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'卯','二月','逢二月： 運势略有起色，且有吉星供照，故必须及時把握良機,以免失之交臂。最需 要是設法舆人多溝通，創造軟環境，對工作要精益求精，以創造硬環境。這 様，事業發展自然順利。','大吉',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'辰','三月','逢三月： 事業大有起色，工作上進展順遂，雖然忙碌，但 劳而有功。最需要是息事事 人，要設法改善人際關係，及時客觀反省，以免因一時之衝動而酸成大錯。','大吉',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'巳','四月','逢四月： 事業運反復向下，因命宮凶星齊集，且無吉星化解，故 必须早做準備,以免 到時手足無措，要遠離損友，以免受其拖累。','平',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'午','五月','逢五月： 事業運每沉愈下，而且還會有很多人事紛爭,不勝其煩。故宜改革求新，慎 142 盲派絕 學 勿抱殘守缺。但因仍有除阻，必須周密策劃。切勿過分依頼他人，以免被人 瞒騙、出賣。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'未','六月','逢六月： 事業運有所改善，良機不断湧現，工作十 分暢順，極易事半功倍。但應謙虚 謹慎，不可自視太高，否則會引起公憤、遣患無窮。要慎防身邊之人，牢記 「堡量最容易内部攻破。,否則,追悔莫及。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'申','七月','逢七月： 事業運浮沈不定，因命宫中有衆多凶星混集，故月初仍會有許多困阻，但月 中會有轉機,並渐入佳境，需要注意是切勿輕犟妄動、冒險玩火，否則只能 是誤己誤人。','大凶',0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'酉','八月','逢八月： 事業運暢旺，不但工作困阻消除，而且會有升職加薪之喜。但必須默默地堅 持下去，凡事儘量親力親為,切勿假手於人，否則將會功虧一 簧。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'戌','九月','逢九月： 運勢急劇逆轉,以惹是非。故事業發展難以一氣呵成 。要注意保持低調,以 和為貴,切勿舆人斤斤計較。必須奉公守法，切勿作姦犯科，以免身陷困 境 。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'亥','十月','逢十月： 事業運勢依然低迷，工作進展出現諸多阻滞，故此切勿太過激進,以免欲速 不達。要及時求變,切勿為一時之不顺而喪失信 心。防意外受傷,月尾正 財、横財均佳，但必須懂得適可而止。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'子','十一月','逢十一月：事業略有起色很多擱置日久之工作均可水到 渠成，但仍需要辛勤耕耘，並切 勿招搖，否则必將功敗垂成。財運仍低迷，必須儘量多諸蓄錢財。',NULL,0);
INSERT INTO "生肖命理庫" (birth_branch,birth_zodiac,category,subcategory,target_branch,target_label,content,fortune_level,uid) VALUES ('亥','豬','流月運程',NULL,'丑','十二月','逢十二月：事業運欲振乏力，工作並不暢順, 但必須全力以赴，以免運居人後。要儘量 忍辱負重，切勿斤斤計較,以免福起蕭牆,前功盡棄。 改名增短 {猪人取名} 宜用之字 1. 猪最喜愛吃的食物為「豆餅』及米飯雜糧,吃艘水是不得已也：如：豆 、豈、豐、 堅、米、粟、梁、精、秀、禾、秉、秦、種、稻 、菊、蘇、麥、稷。 2. 被養的猪，命比較有福氣。整天就是吃喝拉撒睡 。如：宇、家、宋、安、宏、宙、 宜、定、富、蘭、嫻、寬、守。 3. 豬在田間有五榖雜糧可食，自由逍遥。如：田、甲、畢、留、當 、東、甫。 論 命 寶 篮 143 4. 有口福之欲，因此有口主得食之意。但大猪則不喜小洞穴，故宜謹慎用之。如： 口、和、合、周、商、善、回。 5. 亥卯未為三合。卯為兔，未為羊。如姓名有卯舆未之字根，則能大有裨益， 一生貴 人多助，妻賢子孝。如：卯、柳、卿、未、善、義、儀、羡、羚。 6. 亥子丑為三會北方水，故有子』舆「 丑 。之字即與亥成為三會,舆「子』字形通 意者尚有「水」、 北』、「坎。均是，與「丑」字形通意者尚有牛』。如： 子、水、孟、字、存、孝、季、學、承、江、湘、油、河、泳、泉、泰、洋、津、 浩、涵、淳、温、源、牡、特。東方為卯兔、月兔，而亥卯未為三合。同時豬在樹 下，也可獲得短暫的歇息。如：林、森、東、榆、松、 桂、柔、柏。 7. 肖豬之人喜有「金』之字旁，因肖豬為『亥」水；而金能生水，故金對肖猪 者有説 明之意。如：鈕、鈴、鉛、鈞、鎮、銳、鋒、鐘。 忌用之字 1. 猪舆蛇六冲。如：迅、婉、凱、毅、迎、近、返、迪、通、連、道、達、邦、那、 邵、郁、郎、郭、都、鄉、鄧、鄭、延、巡、川、州、之、也、乾、虹、蛾、蜜、 蝶、融、引、弘、弟、強、疆、彎、發、張 、紀、風、鳳、妃、楓、弦、異。 2. 『猪遇猿猴，似箭投』,如「申」、『袁」、「愛」、『 侯』 ·在八字五行中，亥 與申為相害。故犯之、傷人、傷身、傷情， 一切不利。如：申、伸、紳、袁、侯、 九、爰、媛。 3. 猪長大，愈大愈容易上供桌。如：王、玉、琴、玫、玲、璠、珍、珠 、班、理、 瑜、瑛、瑞、瑪、璐、天、太、奇、奂、奚 、長、君、群、帝、將、帥、主。 4. 肖猪之人不宜有彩衣，否則，變成準備奉獻,如：形、彤 、彦、彩、彬、彪、彭、 彰、影、市、布、帆、希、帝、帥、師、席、帧、表、衫、裹、裕、裝、裴、約、 紅、純、素、紹、結、紫、統、維、緣、绮、總、繼、社、祈、祖、祐、祝、崇、 祥、祯、禮、禧。 5. 肖猪之人不喜見到有脚分開之字表，如 ：賢、貴、賓、賞、贊，脚分開代表不健 康，站立不挺。或是姓朱之人名字取名為「家衆』,姓名三個字 均各有一隻猪，合 起來為三條豬，台語云：「三脚猪，殺無肉： ·意味三脚猪，站不穩,無法和其 他猪爭食，瘦巴巴的，不長肉，殺起來怎麽見到肉呢?所以稱:『三脚 猪，殺無 肉」。 6. 其他：肖豬之人亦不宜見到「上」、刀』、「力」、『血」、 幾」、「皮、 石。等不利豬形象的字： 144 盲 派 绍 學 第 式 弟 具 V 草 盲派九星照命法 首派九星照命訣 {串宫壓運訣} 一葳太葳壓運、大耗串宫。二嵗病符壓運、小耗串宫。三葳吊客壓運、五鬼串宮。 四嵗福德壓運、太陰串宮。五葳白虎壓運、喪門串宫。六嵗紫微壓運、太 陽串宮。 七藏大耗壓運、太嵗串宮。八嵗小耗壓運、病符串宮。九嵗五鬼壓運、吊 客串宮。 十葳太陰壓運、福德串宮。十一葳喪門壓運、白虎串宮。十二葳太陽壓運、紫微串宫。 {判断吉凶方法(天、人、地、三才論命) } 在運用『天、人、地』三才理論判断命主九星照命時應清楚以下幾點: 1.天：是天星，九星照命中命主所臨之照命星。天象就是天意( 天時) 。 2.人：是命主生年幹支之納音五行命，命 主生年納音是自身條件，是命主之先天因 素 。 3.地：是流年幹支及納音五行。天象之變化會對地球上一些現象有一定聯繫、變化。 4.命主生年陰陽:凡天幹為甲、丙、戌、庚、王者，生年為陽; 凡天干為乙、丁、己、辛、癸者，生年為陰。 5. 弄清命主生年幹支及納音五行，以及流年之幹支、納音五行。 6. 在分析天、人、地間之關係時,既要看流年天象對命主是吉星照耀 還是凶星加 臨,亦要看流年千支與纳音五行舆命主生年 幹支及纳音五行之開係，從而分析 天、人、地間之生扶比和，刑冲剋破，伏吟反吟。凡事天星為吉星者，其五行助 命主者為吉，為得天時;凡克、耗、泄命主者為不吉，為不得天 時。凡流年納音 生助命主者為吉，為得地利；凡流年納音剋、耗、泄命主者為不吉，為不得地 利 。 7. 以生年納音五行為命，將流年納音幹支五 行定出命主之十神關係。凡是生扶命主 者為貴人，剋命主者為小人。 8. 凡是流年地支舆命主生年地支成刑、冲 、害之不吉之兆，輕者辛苦勞累，重者本 人或相關六親不吉，或有災禍。 纳音年份速查} 甲子1924、1984,乙丑1925、1985:海中金 丙寅1926、1986,丁卯1927、1987:爐中火 戊辰1928、1988,己已1929、1989:大林木 庚午1930、1990,辛未1931、1 991:路旁士 146 盲 派 絕 學 4969235 7650362 王申1932、1992,癸酉1933、1993:劍鋒金 甲戌1934、1994,乙亥1935、1995:山頭水 丙子1936、1996,丁丑1937、1997:澗下水 戊寅1938、1998,己卵1939、1999:城頭土 庚辰1940、2000,辛已1941、2 001:白蠟金 王午1942、2002,癸未1943、2003:楊柳木 甲申1944、2004,乙西1945、2005:井泉水 丙戌1946、2006,丁亥1947、2007:屋上土 戊子1948、2008,己丑1949、2009:霹靂火 庚寅1950、2010,辛卯1951、2 011:松柏木 王辰1952、2012,癸已1953、2013:長流水 甲午1954、2014,乙未1955、2015:沙中金 丙申1956、2016,丁西1957、2017:山下火 戊戌1958、2018,己亥1959、2019:平地木 庚子1960、2020,辛丑1961、2 021:壁上土 王寅1962、2022,癸卯1963、2023:金箔金 甲辰1964、2024,乙巳1965、2025:覆燈火 丙午1966、2026,丁未1967、2027:天河水 戊申1968、2028,己酉1969、2029:大驛土 庚戌1970、2030,辛亥1971、2 031:釵钏金 王子1972、2032,癸丑1973、2033:桑枯木 甲寅1974、2034,乙卯1975、2035:大溪水 丙辰1976、2036,丁巳1977、2037:沙中土 戊午1978、2038,己未1979、2039:天上火 庚申1980、2040,辛酉1981、2 041:石榴木 王戌1982、2042,癸亥1983、2043:大海水 (定命主流年臨九星之方法} 定命主流年蕴何星照命，是按命主虚嵗年龄分男女按九星查表，就可知當年之吉凶 福福。此法雖為簡單,但要緊記口訣;問明命主虚年齡，用九去除餘數明 。除盡無餘乃 為九，有餘查時知何星。 當問清命主虚嵗年齡後用九去除，以餘數分男女來定何 星照命，如果其年齡用九除 盡没有餘數，則按九數來定。例：某男57葳時,問值年何星照 命。 5719=6……餘3,餘数為3,查表可知 值年為水星照命； 2519=2 … … 餘 7, 餘數 為7,查表可知值年為太陽照命。 星數 男女 曜侯 土星 水星 金星 火星 計都 太陰 太陽 木星 屬男 1 2 3 4 6 7 8 5 9 蜃女 6 5 9 8 2 1 4 7 3 屬性 金 土 水 金 火 土 水 火 木 吉凶 凶 中 吉 凶 凶 凶 吉 吉 吉 {論九星訣} 1.曜 侯 男命遇曜侯，言非口舌有。財宜有人爭,顛倒百事憂。 盲 派 九 星 照 命 法 女逢曜侯真不高，步步脚踩獨木橋。招惹是非惱不盡,夜禮多萝睡不著。 羅侯號稱天首坐，吉星相逢權到手。因財招賊命多遭，白手興家買田莊。 憂官失位，重病相纏，口舌失財。羅侯星點本性乖，星點 不記怕有災。小 人將你來盤算，扔下餘頭給你災。 2.土星 男遇土星小人多，六畜不利有病魔。夜夢妖鬼常失眠，遠行謀事定受挫。 女命行年執土星，官司來相逢，出入多不顺 ，提防小人驚。 土星號稱土之精，午宫土逢最發財。中年四十死來催，遷移可免此累贅。 (疾病、牢狱、九月庚辛日) 土星照命心發焦，站不穩來坐不牢。心中發焦眼睛跳，内禮發慌心忙到。 左眼不跳右眼跳，兩個眼睛倒釘著。 3.水星 男命最喜見水星，財喜雙全笑盈盈。添人進口貴人來,富神旅 神到門庭。 水星照命樂自然，夫唱婦隨福綿綿。求財望喜不費力， 一年可坐顺風船。 水星號稱北辰星，智聰技高謀巧變。衣豐食足不愁窮,金榜題 名人稱心。 (口舌、盗賊、忌四月丙戍日) 水星照命喜氯冲，香花飲酒喜來迎。月月不見二層喜，至少也有喜一層。 4.金星 金星照命不一般，男子能把好運添。添丁進口多吉度，禮外喜事榮天然。 女命金星最相當,喜中笑中得安康。是非口舌無大患，身體軟 弱也無妨。 金星號稱太自精，眉目清秀好容顔。早年封侯佩金印，晚景安逸集年年。 (哭泣、刀兵) 金星照命喜氣合，五行是非也顺得。是是非非多足好，出門求財也安樂。 5.太陽 男遇太陽真有理，遠行有財人有喜。君子行年逢此星，哭聲難以找到你 · 女命太陽不顺心，無精打采心發悶。體格軟弱常失眠，悠悠蕩蕩像没魂。 太陽號稱是尊星，官荣身貴入朝廷。進口添丁最合宜，致富發福夀命長。 (加官進祿、年有喜事) 星點至太陽,發福進財鄉。走出常在外，求財保安康。 6.火星 男遇火星真倒楣，總有煩惱把你隨。心焦體弱坐不住，六畜不安须防賊。 火星照命心發焦，坐立不安好唠叨。且防小人暗箭傷,恶言恶 語夢中吵。 火星亦名災惑星，命運安排武位居。生來衣祿似灰微，破財外遇惹官非。 (□舌是非、疾病相继 ) 心情不定上眉梢，主意到有幾千條。南樓望著北樓大，這山望著那山高。 7. 計 都 男命不喜計都來,定有災禍人你懷。六畜不旺多病患，遠行無 法去登臺。 148 盲 派 超 學 4994517 7738509 8.太除 9.木星 計都臨頭不自由，口舌相纏鬥不休。坐立不穩要破財，體 弱多病有煩憂。 計都號稱天尾星，口舌是非起風波。牛鼠相逢喜降臨,惡星同位必為難。 (官符相 纏 、多 憂 疾病，忌五丶六月甲乙日) 計都星點壤，當年心主災。家堂見孝冲，最怕哭聲來。 太陰號稱水之精，温柔豐美光皓潔。早年位高始見菜，貴 人接引笑盈盈。 (貴人迎接、喜慶之事，忌正、九月丙丁日) 女命太陰有災殃，必有煩惱心發慌。要想免災須躲星，先生自然有主張。 金水屬太陰,萬事方顺心。走出常在外，出門逢貴人。 男命逢木星，名利得隨心。辦事大吉利，處處聽佳音。 木星照命激红驚，有財有喜在當年。不落春 天三月禮,必定落在秋冬天。 木星號稱德君子，文學聰明鼕術高。錢財豐 足四方誇,發財發福自成家。 (加官進禄、萬事吉祥) 木星貴人星，發財萬銀丁。走出常在外，求財得春風。 {九星斷訣} 太陽 太陽星照 命(吉星、盛 運 。 萬 事吉，防 冬季有失或不 順 ) 行年值太陽,男人呈吉祥。添人又進口，終葳保安康。 剋命則不吉，凡事細商量。女命與太陽,剋命有災殃。 太陰 太陰星照 命(吉星、進運。知其進退，定會成功 ) 行年值太陰,諸事皆遂心。男女均相宜，凡事 有貴人 · 克命不為喜，女命尤须慎。生身運氯旺，名利兩相襯。 曜侯 曜侯星照命 (凶星潜運，凡事謹慎，待機而動,防是非病難 ) 行年值曜侯，事事多憂愁。男逢遭災禍,女遇也擔憂。 口舌是非起，災厄不時有。平時多晦氣，剋命禍臨頭。 計都 計都星照命(凶星、死運。静守勿動,防受損有病 ) 行年值計都，凡事皆憂愁。男逢也可怕，小心摔跟頭。 是非口舌多，獨木難行舟。女逢更可畏，剋命禍臨頭。 木星 木星照命 (吉星、吉 運 。凡事勿急，好事 自成 ) 行年值木星，全年保安寜。家宅多吉祥，和順且昌明。 剋命则不吉，刀光掠血影。女命也犯忌，受剋事難成。 水星 水星照命 (吉星、喜 運 。防色情口舌， 樂極 生悲 ) 盲 派 九 星 照 命 法 行年值水星，財源多 豐盛 。男人更可喜，福毒均增生 · 命若不受剋，凡事皆順景。男女均怕克，受剋禍不輕。 金星 金星照命( 凶星、生運。明目被遮蔽，謀事皆難 成 ) 行年值金星，災禍易生成。男逢憂慮大，女逢苦伶仃。 生身還算好，受剋災不輕。血光孝服事，也難脱乾淨。 土星 土星照命( 中性星、開運) 行年值土星，小心起官災。出入多不吉，須防小人害。 小心上半年，到秋災不來。受剋煩惱多，生身則悠哉。 火星 火星照命( 凶星、休運。進退两難,不可强行) 行年值火星，噩運心生驚。女人多災難,男人不離刑。 疾病繞身轉,閨房聞哭聲。生身災可免，受剋災不輕。 {九星釋解與運象} 太陽星： 名云太陽星。光輝天下，無處不明朗。主遠行有財,大人見 喜，添人進口， 萬事和合。女人不喜此星，化解方吉。 運象：盛運、離宮。象日：日月光照，四海光明。 凡造作，轉移其他萬事皆吉。投機事業或計畫 ,謀事亦可，但應認真考慮, 防止損失。合夥事宜雖然可行，怕冬季有困難事端發生，宜謹慎。 此年之人運势是驚鳳同時到來之象，是運势最強盛之時期。建築、改建、遷 移，其他諸事都是吉。但是開始新事業或從事投資之事業雖無礙,若不細心 留意，會有意外之損失，故要格外小心。而且冬天時 ,若諸事不踏實,日後 會後悔。 太陰星： 名云注陽星。見官有理，男人出入凡事遂心，女人有疾厄、産患之難。 運象：進運,震宮。象曰：吹氯球渐漸膨脹之意。 通势尚好，多奮發活潑,多得利潤，但急於或過强行事，宜限於失敗 。應聽 從長輩或領導意見,詳察事體,知其進退，則會成功。 此年之運势是猛虎賓士千里之象。是最盛大之運勢,故無論新事業或決 定， 萬事之實行都屬於吉；但是過與不及都不好，有道『過名是失敗之原因 !。 所以應該聽從長輩之勸告，萬事多注意防範,就可獲 得令人羨慕之佳續。 曜侯星： 名云口舌星。主有口舌是非，眼目之疾。女人見血光産厄之災。 運象：潛運、中宮。象日：蛟龍潜在池中之象。 150 盲 派 绍 學 待計畫暫停，修煉身心不可變動。對計畫、謀事、造作、遷移、出行等事宜 延緩。有家庭風波及是非，於人事有損無益。凡事倍加謹慎，尚有病難之 患。 此年之運勢是蛟龍潜在深淵中，雖然有飛上天之勢力，然而現在尚不是時 候，故最好潛居著,暫時修煉身心，等待時機,不可妄動。因此新創之事 業、建築、改建、搬遷、旅行等事情最好延期。因為家中會有人因 口舌之爭 之家庭風波而招致損失。 計都星： 名云凶星。大人不利，六畜不旺，陰人有口舌是非。出入遠行有財,在家有 暗昧不明之事： 運象：死運、坤宫。象曰：萌芽出土，遭受風霜。 好種出好苗，已發芽之種子，最怕出土後遇寒冷風霜。凡事宜守静，勿著急 行事，人反目而遭受損失，有病應及時治療。 此年之運势是等待雪中春梅之象。秋雪很深，梅花未開,因此迷惑多，諸事 不顺遂，多劳心劳力，尤其易産生投機心理。且為了他人之事而招致損失， 會舆近親或好友分離,或被害，最好多注意疾 病。 木星： 名云朝元星。男人有眼目之病，女人有血光之災,不妨。婚姻相合， 人口平 安。 運象：吉運、巽宮。象日：迷童逢貴人引路可達目的。 諸事暢達,無意中好事來臨,但對計畫、事業、進退 等應小心謹慎，以免發 生不利之事，凡事不要貪得無厥，切不要自作聰明。忌舆長輩及上司不和， 否則會出現意外之禍，萬事不可焦急，必可成功發展。 此年之運勢是達到渡口獲得小舟之象，萬事都吉。但新事業要稍加注意，否 则會有意外之障礙,因此不可太自負。要聽取長輩之意見,不可性急， 一切 慢慢來定會成功。 水星： 名云福祿星。大人見喜，遠行有財,添人 進口。女人不得凶災,男不宜渡 河 。 運象：喜運、允宮。象日：著衣錦歸故鄉。 内外喜事多，有貴人或長輩接引。業務上有額外利潤可得，凡事近新氣象 但有雙動,對色情，口舌是非宜謹慎，可免災福， 防集極生悲之欺。 此年之人運勢是穿錦衣又得寶貝之象。實在是好運勢之時期。受到貴 人之提 拔，業務也可獲得意外之利潤;著手新事葉或動身旅行 都無礙,應當注意是 盲 派 九 星 照 命 法 151 非口舌之爭舆色情。 金星： 名云朝陽星。貴人見喜，添人進口，婚姻嫁娶恐有肚腹之災。出入提防小 人。 運象：生運、艮宮。象日：明月被遮蔽之象。 難得發揮其能，自己所有高見,難得他人理解。凡事成功困難,故諸事 應謙 避修養,自然逢凶化吉，雲開見月，萬事大吉利。 此年之運勢是月光穿透雲間之象。表示運势極佳，但猶如時常為烏雲所遮 連明亮之月光也隱蔽般，生活中也常有一些障礙阻断運氟，如難得發揮其能 力，自己所有高見難得他人認同，能將此障礙清除，就可得到本來 之好運 勢。萬事都要留心，多加注意幫助他人及金錢借貨,口舌紛爭之事情，處理 諸事本以謙遜之態度就可得利。 土星： 名云厄星。此年見災不安，家宅不寜，怪夢連連 ,六畜不旺，不利遠行。 運象：開運、乾宮。象日：草木逢霜雪後之象。 待春光一放，即開花發揚。其美麗可結果即時期。應穩妥逐步前進。上半年 平平，下半年大有良機,萬事如意，但勿性急，可保成功平安。 此年之運势是百花爭妍鬥豔之象。以前之潜居運势怡 如洋洋春風,百花綻 放，漸漸開運,因此心祖上若有萬全之準備必然會成功。 火星： 名云災星。主瘡疾，女人産難血光，男人官災不利，人口不安，六畜不旺。 運象：休運、坎宫。象日：但進退兩難,切記忍耐，等待時機。 出行、移動及其他諸事不可强行，以免招禍。 此年之運勢是宿於山中寒寺之象。乃旅居之人疲勞,借山寺留宿之運势，雖 然不是惡運，但稍有停止不進之慮,故若具有堅忍 持久之回復之心，則可成 功。最好不要勉强動土、旅行、遷移，尤其要防病難。 152 盲 派 絕 學 第 参 章 … ……… 盲 派 神 煞 訣 盲派神煞訣 {十二神煞} 1.太葳；2.青龍;3.丧門;4.六合；5.官符； 6.小耗； 7.大耗；8.朱雀；9.白虎；10.貴神；11.吊客；12.病符 {十二神煞歸類} 破財星：大耗、小耗、喪門。 貴人星：青龍、六合、貴神。 財運星：六合、官符配吉星。 小人星：喪門、朱雀、吊客、三吉星被凶星蓋頭、三吉星空亡、三吉星弱極。 官災星：朱雀、太葳被蓋頭、白虎、官符配凶 星。 血光星： 白虎被蓋頭、病符旺配凶星。 事業星： 青龍、六合、貴星、官符配吉神。 驛馬星： 青龍、白虎配吉星、吊客配吉星。 婚姻星： 六合、青龍、貴神、女性：官符配吉星。 文憑星：青龍、六合、白虎。 毒元星：六合、貴神。 子女星： 六合、小耗配吉星。 疾病星：病符、白虎弱、小耗、喪門。 死人星：喪門、吊客同現在四柱、身胎命、入運 為有小孝；兩個以上之喪門同現在四 柱、身胎命、大運為有小孝；大運、胎命身見入耗 配凶星，四柱見喪門、吊 客為有大孝，太嵗加大耗。 命碩星： 白虎、大耗、喪門、吊客。 發財星： 六合、青龍、貴神。 {十二神煞五行吉凶斷性格} 太嵗(小凶)土沉穩重、冷静高傲城府深。穩重老練,城府較深。 青龍(吉) 喪門(凶) 六合(吉) 木很仁義、善良傲氣不瞧人·仁慈善良，溫和親善。 土很頑固、脾氣倔強拉不回。倔強固執，木的小性。 木和蔼人、和氯交人好關係。善於交際,舆人和合。 154 盲派绍犟 官符(中) 土很大氣、大度高雅好表現。高貴典雅，有風度氣質。 小耗(中) 水很謹慎、錢在手禮如流水。心 急性直，不善理財。 大耗(凶) 火能花錢、没有計劃太隨意。彬彬有禮温和，做事也是很得體。粗暴豪 爽，打抱不平。 朱雀(小凶)火脾氯急、能言善辩惹是非。直來直去，言語得罪人。 白虎(凶) 金很好勝、剛強誠信重信用。喜怒無常難琢磨，直來直去得罪人暴躁急 性，惹是生非。。 貴神(吉) 土很高雅、喜怒埋藏在心禮。雍 容華貴,慈眉善目。 吊客(中) 金很固執、脾氯倔强不回頭。 憂鬱寡斷,心事重重。 病符(小凶)水有病態、外柔内剛很謹慎。無病呻吟，惜力悲傷。 {十二神煞顯示疾病部位} 太葳： 腦部疾病、脾胃、皮廣。 青龍: 神經系統、四肢、酒色病。 喪門: 脾胃消化系統。 六合： 花柳病、眼睛、腎病。 官符： 脾胃消化系統。 小耗： 經絡、小腸。 大耗： 大腸、盲腸。 朱雀： 眼睛、心臓病。 白虎： 骨質、血液疾病。 貴神： 脾胃消化系統、神經系統。 吊客： 肺部。 病符： 腎病、肝膽疾病。 {流年神煞} 太葳(建) 壓運主不祥，喜神忌神有分張。太嵗要與兇殺並,必有哭聲在廳堂。 府上若有高堂在，精心料理不得間。高堂不見財有損,嵗中多事少安然。 青龍(除) 入運喜衝衝，定有喜事到門中。大喜家禮添人口，小喜田宅入 門庭。 求財問喜都願利，出門辦事得顺風。事業多 得貴人助，心想事成在嵗中。 喪門(滿) 壓運多穿白，不見孝服傷錢財。 二限入運防宅長,運如三限身有災。 盲 派 神 煞 訣 155 官非口舌常相伴，小人背後把髒栽。多寬心來多隱奈， 無病無災福禄栽。 六合(平) 進田宅，除病生女孩。紅藍雙喜現,必有喜事 見。求財財可得，求喜喜自 來。 六合喜事多，送酒又添席。有妻生貴子，無妻藏嬌娥。 官符(定) 壓運運不安，不見疾病必見官。玄武並臨防贼盗，官非口舌在今年。 官臨金神西方忌，官臨木神忌東方。命中喜神臨太嵗，求官進職喜開懷。 小耗(軌) 壓運淚紛紛，命中忌神剋子孫。房房子 孫太平日，難猪牛馬不過冬。 衣物錢財多有損,出門辦事費精神。若是用神命中占，不需勞 神進門金。 大耗(破) 壓運溪濤濤,引動年柱必見孝。宅中高堂不在位，強盗入宅災難 消。 若是命中喜用神，無病無災自逍遙。流年運星有喜忌，命局有福災自消。 朱雀(危) 壓運主不合，其年必定有口舌。官非口舌隨運轉,家禮家外 是非多。 少説多聽人人敬，多嘴多舌損威名。東家長來西家短，不需勞神費精神。 白虎(成) 忌神當頭坐，自身無災必有禍。子 孫錢 財都安樂, 官非口舌難躲過。 出行若往西方去，須防刀槍與馬戈。車前馬後多留意，處事留神少折磨。 福德 (收)流年喜事生，定有喜事到門庭。未婚之人大婚動,家有賢妻貴子生。 應舉求名都得重，為官在職要高升。葳臨桃花裙下敗,十程八村有淫聲。 吊客(開) 壓運要穿白，不見孝服耗錢財。白虎星辰來做主，年中自身定有 災。 沐浴桃花臨身地，多淫多病命中排。太嵗要把用神見,福壓百禍命中該。 病符(開) 壓運不自由，前程事業有阻流。流年大運病符見,傷 財惹氯病床頭。 病符陌越來,文章雖然高，外面朋友要少交。自己錢財守 ，莫向光棍打交 道。 {流年吉星詩訣} 贵神： 順風行，貴神百事昌，男女大吉祥。處處貴人助，人財雙雙旺。 青龍: 貴人逢。 六合： 生意隆。 紫微： 带貴人，有財有喜，壓兇殺,化凶為吉，保身安事 ，萬事稱心。 紅驚： 红驚如命富， —葳喜重重。君子加官職, 常人管運通。 天喜： 天喜來臨命，流年主有財。百般作事吉，欣喜笑顔開。 天德： 天德命中逢，經管事事通。男女婚姻吉，喜氯二三重。 天解： 天解臨命位，碌碌最高強。能解百兇殺,四時降吉祥。 156 盲派絕 學 月德： 月德入命宮，見災也不凶。逢危當有救，遇險反事通。帶貴人 · 太 陽 : 太陽值流年，祯祥百福全。財禄從天降，經管獲利源。有喜有財,陽勝陰 衰，男泰女否。 飛尉： 飛財人命強，事事最相當。名利經管者，逢 之大吉昌。 驛馬: 驛馬喜匆匆，逢之命運通。若求命與利，任意走西東。 文星： 文星大吉旺，管謀萬事強。四時皆吉利，男 女盡祺祥。 催官： 催官吉事多，值此吉高利。轉遷皆遂意，步 步是亨通。 { 流 年 凶 星 詩 訣 } 血刃： 血刃值流年，其年福患連。若無官事拖，必主孝服章。 勾絞： 勾絞不堪災,遭官要破財。百般間事擾,口舌便建來。 白虎： 白虎更難當,妻現定損傷。破財膿血侮，六畜亦遭殃。破財、带孝服 、傷人 口或損傷或車禍。 天哭： 天哭鬧啾啾，須防孝服猶。官災並火盗，謹 慎慢行舟。 披頭: 披頭不敢當,值日見血光。若無災舆孝，□舌二 三場。 恶煞： 恶煞是喪門,降災不可脫。破財及亡喪,孝服怎 離身。 喪門: 喪門是哭神，落淚悲哀聲。疾病多為害， 災難近身邊。注意有喪,犯喪帶孝 或逢不幸，勿送葬、探病、哭聲起。 吊客： 吊客主生災,流年定破財。官司並口舌，疾病主悲哀。行災 禍。主行喪,是 非有刑傷。男女都不順,小人送災殃。 飛廉： 飛廉殺最凶，災禍二三重。瘡疾連綿起，膿血滿身紅。免災並口舌，開事煩 心懷。 病符： 病符疾病凶，膿血及瘡疤。若還無喜孝，口舌悶心胸。生病、破財、易患病 災。病符不凶星，作事不順心。煩惱心不安，災難傷亡病。 死符： 死符忌死亡，百事見乖張。不然防小口，閑 非反福殃。 大耗： 大耗葳君逢，不利是經管。錢財多耗散，産業化清風。多耗損、防強盗、失 大財。大耗本不祥，父母病有傷。小人反目害，耗財有災殃。 五鬼： 防疾病、孝服、破財。認事多，拖累章連官事之災。 小耗： 疾惡纏身，官災破財傷痛之災。難太平。 天狗： 防口舌，有狗之地方防被狗咬傷。 太葳： 血光臨,太藏壓運來,無病必損財,煩心事不 顺，□舌是非來。 盲 派 神 煞 訣 157 官符： 官非到。 朱雀： 防 | 文書口舌。 {神煞論} 天乙貴人： 天乙入局旺得生，形貌軒昂智聽明。不犯刑剋不犯 險,出入總有人來 敬。舆殺並臨貌有威，喜避近貴器難成。 天月二德： 天德原來大吉昌，修文必定登科甲 。平民管謀百事強，兄弟妻兒無剋 破，貴比汾陽富石祟。女逢天月二吉星，嫁美夫生聰秀貴子，利座無 凶，最怕自遭冲剋，則必然無力。 喪門、吊客： 又名地喪,主喪服，破財之事。 災殺: 申子辰見午、亥卯未見酉、寅午戌見子、已酉 丑 見卯。福少褐連綿,主 血光横死，在水火防焚溺，在土防墜落瘟疫，剋身大凶，若有吉神相 助，多有武權。 劫 殺(之神 ):申子辰見己、亥卯未見申、寅午戌見亥、巳酉丑見寅。吉則聰慧過人， 才智超群，事不留行，胸羅萬家，高明爽遭，武德衡財。凶則昏濁邪 侈，毒害性重，宿疾刑徒，兵刀折傷,執拗内狠，貪奪無情。 血刃、流霞： 舆身體受到傷害有關:輕者皮肉傷折，血光之災,重者會有生死意外之 福。男命因酒色易犯血光，女命易有産厄、血崩之災。外出、開車須加 小心，防意外發生之嚴重性增加。 子午冲： 子為帝位午門庭，子寒午炎剋又冲。愛惹是非過日子，工作事業常雙 更。日思夜想難清開,奔波勞碌不安寜。異性缘重常乎鬥,離家返回好 折腾。想事雖多常雙化，失敗損失會發生。病在肌膚與心臓，血液心賢 脈搏輕。子午相冲定剋父，過房人繼必無差。空神若是來相剋，無害妻 兒損自家。 一身不安。 丑未冲： 丑為道教未佛教，大吉小吉土相冲。女命夫君情人找，兄弟緣薄少親 情。難得長輩相助力，謀望雖多少收成。冲為凶時事多阻，陰怪之事會 發生。佛道禪法有興趣，善研星象與氣功。脾肺多疾虚又喘，腹疾痢疾 消化道。 丑 未相冲帶疾多，若然水命主比和。生身父母無刑剋，兄弟相 冲主過窩。凡事多阻而逆，冤仇詛咒，語言衝突，不打仗。 寅申沖： 寅為鬼門申人門,功曹傅送剋又冲。夫妻同床 有異心，男女相逢婚外 情。愛管開事招是非，小人不断口舌生。吉時可走經商路，凶時鬼邪常 158 盲派絕 學 卯西沖： 辰戌沖： 已亥冲： 作祟：相信鬼神講迷信，神秘文化興趣濃。口苦舌幹易香迷，肝膽便秘 胸神經。寅申相沖命不長,還兼帶疾産中亡。可祈夭神來保佑，免使父 母哭断腸。多情又多敗,且好管開事。 卯酉日出日落門,金木相剋又相冲。桃花威池臨身上，婚外之戀起紛 乎。憂愁多勞不易財，背約失信無真情。職業長久也常變,地域住地常 變更。逢事考慮欠周到， 一生難以得安事。病在肝 膽舆肺部，治療筋骨 免身痛：卯酉相冲剋自家，父母生來生有刑。若然三葳無刑剋，七葳嗚 呼喪黄泉。六親無義多憂愁，多為親朋而憂,背約失信，憂慮多勞,色 情糾紛。 辰為太陽戌日落，天羅地網二土冲。吉時此人整名顯,凶時虚詐無真 情。夫妻感情不融洽，奔波勞碌過一生。男逢少兒多是女，女逢易犯婦 科病。爭強好鬥犯口舌，剋妻傷子命早終。病在膀胱皮膚處,恶寒小腸 頭又疼。辰戌相冲主過房，若然不死也驚狂。四葳恐怕離父母，身弱帶 疾便喪亡。爭認鬥打，剋親子。 已亥馬星又文昌，水火相剋又相冲。吉時此人才横溢，凶時壓抑不安 生。愛管開事話語多，助人為集獻真情。付出太多回報少，順來逆受常 出行。工作住址常變化，日時逢之女多情。病在肝腎會吐瀉，時刻預防 糖尿病。已亥相冲病難多，必然離祖又離家。若然父母 無刑剋，七葳中 間必折磨。喜助人而己不利，多管開事。 { 地 支 相 刑 } 寅已申無恩刑：其性多冷酷，薄情無義,甚至恩將仇報,男易遭殺傷、血光、牢獄。女 多損孕、獨眼、傷殘。寅已申支三刑臨,為人驕傲不虚心 。逢場作戲顯 自己，眼中没有周圍人。為官不利易口舌，為民詞 認開糾紛。易有破財 事發生，三教九流圈中人。 丑未戌持勢刑：多夫妻敵視,體弱多病。女命與夫家不和，孤獨清冷，多有病傷災咎。 丑 未戌支三刑臨,持勢財黑心又狠。為人是非爭 長短，家庭不和口舌 频。為官不順易免降；斤斤計較不合群。看誰都是不順眼，從早到晚總 煩心。 子卯無禮刑： 風流淫亂無禮節,其災禍多表現在色情上及六親間之矛盾事件，或因無 禮而觸犯刑法。子卯地支三刑臨,為人無禮少義人。有職有權虚仗势 盲 派 神 煞 訣 159 為民打腫充胖人。遇事總愛挑毛病，自尋苦惱 不順心。大事無能小不 幹,財不興旺自孤貧。 辰午西亥自刑：自我刑傷,其性自私頑固，心毒手辣，乎名奪利，夫妻仇視。沉静内 毒，機變權謀。辰午酉亥自刑臨,隨心所欲苦自尋。六親緣分太淺薄 關鍵時刻無幫人。靠山山倒靠河幹,為官為民心不順。註定一生張羅 命，自力更生要勤勞。 {地支相害} 多用在性格、感情、人際關係中，彼此損害之意； 含有六親間之損剋開係。害者阻 隔、爭鬥。 寅已相害： 寅已相害逞害能，六親不合多口災。 一生 奔波勞累命，多見體弱病常來。 謀事阻礙困難多，事與願違鬧心來。腸胃患 病常呻吟，肢體傷殘註定挨。 卯辰相害：卯辰相害欺長害，事業不順鬧心懷。好事難成想成 空，婚姻不顺口舌來。 遇事乎奪難如意，自尋苦惱欺聲唉。六親無 靠各顧各，易遭外傷碰撞災。 申亥相害： 申亥相害爭進害，嫉妒才能眨人才。旺時神清貌又秀，或喜或悲變化快。 還差多謀事少成，怨天怨地不應該。身體患病傷骨疾，臉部損傷破相來。 酉戌相害： 西戌相害嫉妒害，夫妻不合口舌來。事業不順小人多，不明原因人指責。 幼小損傷災疾多，為人處事好又壤。平生頭面多生瘡,易遭燙傷舆火災。 丑午相害： 丑 午相害官鬼害，婚姻不順口舌來。兄弟不睦常吵開,兒女難管牽連災。 事多阻礙或難成，有理難辯違心懷。若逢生 旺性暴躁，腦部神經病患來。 子未相害：子未相害勢家害，劉親骨肉建心懷。營謀困難阻滞多，易 遭官非訴讼災。 遇事有始難得終，時時提防小人害。男人易 患脾胃病，女犯婦科或墜胎。 註：凡是流年地支與命主生年地支成刑、冲、害之 不吉之兆，輕者辛苦劳累，重 者本人或相關六親不吉，或有災禍。 七十四神煞 1.太葳；2.青龍;3.六合；4.喪門星君；5.五鬼；6.官符；7.小耗；8.死符；9.葳 破；10.大耗；11.紫微；12.龍德；13.朱雀；14. 白虎；15.福德；16.貴神；17.天德； 18.天狗；19.吊客；20.病符；21.天喜；22.威池 ；23.血刃；24.女犯河魁；25.亡神； 160 盲 派 絕 學 26.吞陷殺;27.指背；28.劫殺;29.寡宿；30.天哭；31.災煞；32.紅豔;33.欄杆； 34.披頭;35.華蓋；36.三刑；3 7.羊刃；38.子卯刑；39.红驚;40.天厄；41.地殺 42.勾绞；43.太陰星君；44.劍鋒 ;45.伏 ；46.太陽星君；47.天空；48.晦氟；49.流 霞；50.驛馬;51.将星；52.金匱； 53.孤辰、寡宿；54.男犯天罡；55.月德；56.男女犯 命星；57.貫索；58.卒暴；59.飛符、暴 敗;60.黄幡；61.板鞍；62.囚獄；63.天殺、葳 殺;64.六害；65.八座、解神、地解：66.月殺;67.捲舌；68.飛廉； 6 9.的殺;70.破碎 殺;71.陌越；72.地殺;73.年殺;74. 月空； {神煞歌訣} 将星及三台，百謀事和譜,出入必稱意，添喜又添財。 天罡羅計臨,三殺年中尋，男逢恐兇除，女值有災星。 红鬻舆天喜， 一年皆歡喜。百事滔滔顺，財喜不须疑。 華盖驛馬星，值年必不定。千思萬條路，不若苦管生。 天月二星臨，值此多安事。 一年滔滔顺，添財又添丁。 太嵗當其年，出入欠安寜。單月大不利，災厄小人章。 太陰連太陽,一年大吉昌。東作西成就，家計保安康。 白虎舆飛廉，災厄小人纏。失物恐嘔氯，提防麻衣穿。 玉堂文昌星，四季多康寜。謀為皆稱意，災禍不纏身。 勾绞皆稱意，災褐不纏身。小人災厄有，幸遇貴人解。 災殺病符運,值此多不顺。男遇恐失財，女逢有災星。 嵗破兼欄杆，逢此大不安。損财嘔氯有，不然病福纏。 血刃浮沉臨，血光要小心。謹慎二字好，不然恐跌傾。 天解加地解， 一年事和谐。謀為稱心意，添喜更添財。 官符是官非，忍耐和為美。小人口舌有，謹慎免災厄。 劫殺死事臨,失財小人侵。單月小心好，陰多卻少晴。 龍德加紫微，逢之多祥瑞。求利利萬倍，求名身荣贵。 天狗连吊客，究惡不可説。女逢有虛除，男逢恐失跌。 捲舌逢桃花，口舌不可詩。任你獨宿坐，是非雨交加。 天罡天空星，人品欠安事。若不見孝服，必定災福侵。 大耗逢丧門,失散葬子聲。 一年啾唧過，有解不見刑。 天殺遵地殺，是非两交加。小人災厄有， 一年亂如麻。 盲 派 神 煞 訣 161 天臺月殺來,謹慎小人災。單月恐不利，提防要失財。 如犯千斤殺,家宅敗六畜。天轉須恶死，地轉须架喪。 喪門見丧門,必定有哭聲。大耗傷父母，小耗不太平。 流霞一來到，必然血光臨。鐵囚關一到， 一路丧黄泉。 鐵舌臨弱地，車禍要大忌。人若犯懸棵，喝蘖自缢亡。 土牢關病，男牢女命天。男女妨家宅，敗決妨家財。 {流年神煞具體用法} 從出生年(生肖)起，依次順數下來,每十二年循環一次，因而複試,直至人生命 之結束。流年神煞只依頼於生年，不依賴於人之八字。 無論男女，1 .【其出生之年】 ,及在以後之葳月中與出生年支相同之那 一年，其都 將遇到流年神煞；「太歳」「劍鋒』 伏屍』。逢「太歳」是年不宜動土，不宜修房修 路；逢「劍鋒。防刀槍之傷;逢『伏屍」人易生病，宜保養。2 . 【其出生之第二年】 , 要遇到「太陽』 天空』。「太陽』此年將光彩照人 ，可以有所作為;『天空』意味著 此年易出現空忙之情形。3. 【其出生之第三年】 ,要遇到『喪門。神煞，表示六親此年 可能要失去親人。4 .【其出生之第四年】 ,要遇到「勾絞」『貫索』,預示著此年要遇 到不顺心之事；易被人偷盗財物或易丢失財物或被受騙。5.【其出生之第五年】,要遇 到”官符。 五鬼」 ·預示著此年要遇到舆官方打交道之事，可能舆打官司或有些麻煩 事，或易遇到一些莫名其妙之事，讓你無可 適從。6 .【其出生之第六年】 ,要遇到「死 符』「小耗』 ·預示著此年自己或家人易生病，嚴重者還有可能導致生命危險 ，或易破 財，要有損失。7. 【其出生之第七年】,要遇到『欄 杆」 大耗」。預示著此年會被絆 住，諸事難展，總要經歷一番努力，才能有所收穫，或此年要有比較大之損失，或被人 偷盗，或因某種原因而破財。8 .【其出生之第八年】 ,要遇 到「暴敗』『天厄』。預示 著此年大起大落，有從高峰跌到谷底之危險;或易遭天災人禍,勿輕舉妄動。9.【其出 生之第九年】 ,要遇到「白虎』 飛廉』 ·預示此年易生 摔跌之事，或有血光之災, 且易有口舌是非。10.【 其出生之第十年 ，要遇到「福星」 捲舌。。預示著此年逢 貴人，易得貴人之助，但有是非，家人易有災難。11. 【其出生之第十一年】 ,要遇到 天狗。『吊客」。預示著此年奔波不停，會有收穫；但家人可能會出現 病人，甚至要 喪六親。12 .【其出生之第十二年】 ,要遇 到「病符」神煞。預示著此年本人或家人要 生病， 一年不利。 162 盲 派 绝 學 {神煞總論} 太嵗— ——藏伏屍劍鋒星，意外事故多發生。少惹是 非少近官，閉門不出忍修性。 太藏當頭坐，無災必有禍。任你鐵羅漢，也要受折磨。太葳為首中性星 遇贵則吉逢殺凶，只要太藏在地支，事事憂 愁不安寜。太葳壓通不是福就 是福，是福無限好，是禍躲不過。他人間事莫要管，防備自己得安然。 太葳為中性星，遇吉則吉，遇凶則凶，無論見吉星還是凶星，只要太嵗在 地支上即為凶。太葳壓運心發焦，心驚眼跳不安牢。今 年該把婴兒見,見 著喜眉俏。大喜小喜全不見,夜間有覺睡不著。 太葳當頭運不通，生意買賣落場空。求財望喜多不順,終日總把悶氣生。 暗地陰人口舌起，小人不足事不成。四柱官殺多太重，足有六合保太平。 男犯太藏運不安，恐怕傷財事鬧翻，六七月裏全記住，十月臘冬得安然。 太葳之年多憂愁，口舌臨門不自由。疾病纏身小人侵，婚姻錢財莫强求。 運嵗太葳難行舟，勸君持重可遠避。 太嵗星君：太嵗者即六十甲子值年之嵗神，掌握人間之福福，道家以其當 值一葳之主宰，故稱嵗君 (值年太嵗 )。「太藏當頭坐， 無喜必有禍。 , 宜安奉太葳，此年行事易極端，有喜事則行事顺利，如犯之必凶， 没好結 果，故少變動,謹慎保守。太多資訊回鑽不利，多逆境、煩心 得很、麻煩 事多，不是上下開係没有理順，就是左鄰右舍相處不安；若自己不傷則傷 他人，傷妻子或失財,包括投資決策失誤。嵗臨今年有三忌：不参舆白 事、不参與觀新房、不探望病人。否则晦氣降臨,百般不順。 青龍— — 青龍旺盛喜事多，就怕頭上蓋凶星。 青龍是喜神，大喜有幾重。荷生生貴子，門前應掛紅。 青龍為吉星，旺為吉，見吉神吉，被凶星蓋頭則凶，被中性星蓋頭亦吉。 青龍星辰喜九天，花開正紅月正圓。男女占此多吉順,重重喜事近身前。 青龍入命大吉祥，創業謀事有人幫·添丁進口生貴子，家中喜事一椿椿。 官運亭通財運好，即使有禍不為殃。命占青龍利求財,離祖出外貴人撞。 今年必定多吉度，添丁進口喜氯來。男占青龍是喜興,諸般事兒定太平。 六七月裹諸事好，十月臘冬也興隆。 六合——六合為吉，主喜慶。六合有喜財運好，就怕惡神來相冲。六合見嵗合，定 是喜事多。有妻生貴子，無妻娶嬌娥。 六合星辰笑颜開,和順生風聚生財。男女犯此多平順,又有喜來又 有財。 盲 派 神 煞 訣 163 命占葳合運氯通，出外求財保安事。生意求財千倍利，發達如意百事 通。 添人進口生貴子，最怕小人入宅中。男犯六合神，事兒不爽身，定記 八、 九月、臘冬離了身。 六合人命大吉昌，萬事順遂人丁旺。多得親友來相助，縱有逆風不起 浪。 求財求利皆如意，添喜進财時運強。 喪 門 星 君 一 三 主孝服哭泣。命逢喪門舆地孝 ，孝服小災當年中。倘若家中無内孝，外孝 也得去奉行。 丧門主病亡，不驚也心慌。若逢走冠馬,發跡在他鄉。 喪門破財小凶星，最好為弱或落空。 喪門是小凶星，弱為吉，空門為吉，若被吉星蓋頭則應小凶。 喪門壓運事不安，是非口舌在眼前。平時撒下天羅網, 他人有事把你連。 小人多來贵人少，家門不幸被禍纏。 喪門見喪門,今年淚淋淋，命犯大堂哭蟹有，不哭旁人哭自身。四柱官殺 多太重，還怕羊刃本命中。謹記正、三、九月，冬至月裏得太平。 行年主事逢喪門,苦苦如淋淋。男怕傷財氣，女怕不順心。□舌隨便起， 辦事禍來臨。不把重孝見,準備哭親人。 命犯丧門不宜送葬，探病及觀葬禮,防孝服臨身，破財 難免，家小病痛， 有時甚至將帶來相當之不幸或災危，如欲變 動或創新，應特別小心謹慎為 之，宜制喪門星符，將喪門星符佩帶在身即可。 丧門入宮，不利探病、送喪、以免受災禍， 生不意事端，避者則吉，百事 無憂。宜制殺兇星，以保平安，無解恐有平地起風波，凶多吉少，須蓬慎 防之免擾。 五鬼— —五鬼官符陌越位，牢獄官司難變更。平地是非官司起，暗地有人把你整。 五鬼本不良，陰邪主災殃。小人多暗害，疾病防損傷。 五鬼人命雨邊排，初一十五好開災。熱了好象蒸籠様，冷了好象冰水 排。 冷了一陣熱一陣,頭迷眼花發躡呆。腰酸 背痛前胸悶,大脖發短頭難治。 一天好來一天壤，此病好似兜裏揣。 五鬼佔宫，防人之災憂,無故生煩,此年中以制五鬼運財,逢兇化吉。無 白事端來,六畜不旺破錢財，合股事葉不利，虧貴,若口舌，纏官非，致 受災厄囚獄苦。此年開事少管，勿食花好酒 ，忌進賭場,易招惹官司或小 人暗算，官非損財，言談謹慎，易得罪貴人。宜制 官星符，每年雨水前拜 164 盲 派 经 學 祭，將五鬼符與錢紙一同燒化，五鬼自然運財來。 官符 — ——官符红驚是中性，有喜定在當年中。 官符為紅驚，有喜在當年。少惹是非事，免禍在 身邊。官符為中性星，官 符為工作： 官符星辰坐當頭,□角是非不周流。最近要把小人犯， 莫去求財莫違避。 官符入命令人愁，是非口舌無止休。平地也會起風浪，憂思如麻無有頭。 財帛易散物易失，犯了官符難自由。 行年官符是凶神，扛夾帶鎖牢門進。若要不把牢門進,口舌是 非找上門。 車前馬後加防備,刀镰射斧要傷身。時來運轉人欺鬼， 運去時衰鬼欺人。 小耗— ——命逢小耗死符星，損物破財數已定。謹防小人生禍端，遇事要把貴人請。 小耗大破定不祥，財損人傷有人攻。時運多顛倒，做事不牢靠。金銀多耗 散，家财遭鬼盗 · 小耗主小凶，破財、花錢多存不住。 小耗壓運性氣歪，莫生開氣怕生財。少管開事少説話,一管事情口舌來。 女犯小耗外孝冲，主有家喜到門庭。家喜外孝全不見, 不過打春不顺通。 小耗之年多煩惱,是非口舌幾多遭。官非易起氣易惹，金銀錢財有損耗。 東奔西走無閑處,辦事不遂多阻繞。 行年小耗在當年，挑三揀四在兩邊。當你面前説好話, 背地就把歹心安。 將你推到房頂上，你上房他把梯搬。將你摔倒溜平地，小人在旁假犯 難。 死符 —— 死符大禍來,凶亡主大災。重病防跌傷,是非破大財。 人入死符最是凶，錢財六畜總成空。夜知盗賊小人侵，口舌是非不安寜。 傷財若氯進官司，無事無非禍重重。家中老少爭吵鬧,接連就把開氣生。 死符小耗入宫，賊神當道，不利於與人結黨合夥經管事業,勿探病人，無 中生有，若探病代人病，見屍恐致亡，避忌為妙。 是非星，不利喪家，不宜參加喪禮,易招惹官災,訴訟等事。防被偷盗。 宜制死符星化解，七月十五前，用死符與替身，銀紙焚化，可保平安。 葳 破 — — 命逢欄杆並嵗破，但行好事貴人通。大耗破財防水 火，防人拐騙把病生。 太葳對冲來,無病必損財,辦事不顺利，是非口舌來。 葳破大耗，防人之憂,五内生憂,災退在月恩日拜神吼祈，事能忍耐守 分，自可無憂，忌動土，完婚，如有結婚者 ，破害夫妻，半途無緣，或乏 子息，色欲謹慎，事業不順而破財。 盲 派 神 煞 訣 165 大耗 紫 微 — — 龍德—— 太嵗逢冲，吉兇二極,災禍纏綿,易生曲折而破損財 運及財物被盗，易遭 官事、糾紛、疾病、失信等事，親友負義,求財求利事 舆願違。五月初五 前，以嵗破符與替身，銀紙焚化，可保平安。 大耗定不祥，父母有丁傷。破財損人口，朋兄白眼狼。 大耗主大凶，大耗與喪門,吊客相並,定主重孝。 葳逢大耗禍非輕,官司盗騙極易生。不是破財遭凶事，就是體弱身多病。 若舆白虎連一起，凶喪孝服災更重。 行年大耗時運低，應該在外把家離。如要在家多不順，氟惱 傷寒做痛疾。 披麻帶孝靈前走，也許傷親哭啼啼。 紫微龍德能照應,增人進口喜事逢。命逢暴敗 天殺臨,□舌小福有虚驚。 紫微本相親,感情人迷津。勾絞桃花笑，色災不安寜。 紫微入宫本不離,當年做事腰杆直。遠處求財更風順,近處求財也随心。 犯點小人不丁事，求財望喜八九分。傷點小財進大財,逢凶化吉有貴人。 喜事重重，此年有喜逢為貴,無喜事端來。如添丁進口， 大利運行有財事 可成，欲求財利旺，此年正月十五日夜求龍德星神，則百事大吉。 龍德人命喜氣生，四季八節得安寜。貴人當旺好辦事，求財諸事都順通。 男犯龍德離家好，女逢龍德喜三層。人也旺為 財也旺，滿園鮮花数你紅。 年逢龍德，吉星降蕴，逢凶化吉，喜上加喜之作用 ，去年之徽運已經消 逝，財氣勝過去年，是最難得之一年。貴人相 助，諸事皆吉，災禍不生， 猶如錦上添花，夫妻多情，男女有愛,家庭美满，合 夥易成，宜把握機會 發展事業: 朱雀——朱雀大凶□舌多，瓣事曜嗦小人横。 朱雀見朱雀，口舌是非多。有理無人理，還要背黑鍋。 朱雀大為凶星，主官司口舌，小人攻撃。 朱雀壓通事難安，無财無勢也遭官。無形就把 小人犯，暗犯小人把你纏。 朱雀入命口舌生，招引災禍可不輕。求名求財 都不利，風波擾得心不事。 幸喜紫微當頭照，逢凶化吉保太平。 白虎- 主官非病破。命逢飛廉舆白虎，血光横 禍孝服用。不是内喪必外孝，不然 天天把病生。 白虎主血光，車禍有刑傷。小人來暗害，孝服免災厄。 白虎當定災禍起，若被蓋頭更是凶。 166 盲派超學 * 白虎當頭坐，無災亦有禍。天上掉地裏冒，意外之事都來到。 白虎為大凶星，不可被任何星蓋頭,蓋頭必凶。 行年白虎諸事凶，無事無非有災星。閑來無事家中坐，坐立不安不順情。 每年辨事事辦好，今年音同字不同。不打官司口舌犯，嗓嗦事情辦不清。 白虎入宮為害，恐傷人口，血光病難,外傷困危痛運,及其他不朔之事。 女人有喜即吉無喜憂,此年中夜間拜麒麟星降臨,宜制化白 虎凶星為吉 妙。 白虎星君；遇此星君值年，應防止意外災害，尤其是車福；家中不和、朋 友翻臉、或生病孝服，是非纏身，破財難免，初一子時用針把十個 手指頭 之血取一黜放入臉盆洗臉,即化解矣。以白虎星君與三牲祭送，舆替身、 銀紙焚化可保平安。 福德- 命逢捲舌福德星，小有口舌不用驚。天德福星貴人助，求名求利必順風。 捲舌有口舌，是非不和諧。損財生氣恨，天德化災厄。 福德星入值，萬事吉祥，如有不足事，可在每月初一 、或十五日早晚敬拜 福德正神，招財童子，進室童郎，求之福郎，無求不利。 福德之年，如能掌握其法則,會有財利及貴人相助，財源廣進,事業 發展 宜惜福守規,善用能源，可化解凶呈附身，可多拜五路財神，招財童子 吉祥星君，或在每年中每月初二及十六日燒化五方財神金。 貴神 — — 貴神壓運好事多，財喜雙全樂不停。 贵神壓運事吉祥，財源茂盛達三江。女見貴神喜慶多，男遇貴神天賜祥。 贵神為吉星，貴人相助，遇難呈祥。 貴神壓運笑可呵，出門在外貴人多。家裏外面人緣好，見喜重重剋曜嗦。 贵神入命福毒長,財運暢通身安康。善於交際受人敬，高官厚祿名氣揚。 凡事都有貴人助，運逢貴神心歡暢。 天德 — — 命逢天 德多吉利，男女逢之世間稀。男命富貴能長久，女命逢之更出奇。 不犯刑剋不犯盗，遇事逢凶能化吉。 天狗——命逢天狗及吊客，剋兒剋女有災星。不是守喪便守病，必防親人不太平。 天狗大災星，口舌不安事。木土為死訊,破財恨不平。 命入天狗運氯缩，剋著子女受折磨。恐怕明搶容易躲，最怕暗箭難防著。 暗有小人把你壤，捎帶開氣把火窩。 天狗星入侵，忌看食日，免逢凶災,以生測福與大破財，此年中夜間直改 盲 派 神 煞 訣 167 從天狗凶星化吉，無解凶多吉少，须有不意煩惱及病痛之憂。 天狗星君(竊 盗星 ),不利遠行，少出門,外出不宜鬧事，易遭小人陷 害，盗賊破財,血光之災,官司等事，勿舆他人有金錢往來,遇事勿逞强 或輕舉妄動。宜制之，七月十五前将天狗星符和三牲祭送，可保平安。 吊客— ——: 主孝服哭泣。吊客壓運事有凶，即有是非開災行。男犯 吊客主不順,女犯 吊客主災星。 吊客為小災星，偏孝星。 吊客流年必有凶，需防親人不太平。不是内孝就外孝，晦氣之事多重重。 葳逢吊客心不安，舊愁去了新愁添。 吊客壓運是神奇，朝天每出心發虚。夜間常把惡 蘿做，心驚眼跳不吉利。 吊客入命不尋常，行走坐隊不安康。無缘無故自數氯，稀裏糊塗顛倒忙。 吃穿不缺無興趣，總想喝藥去懸棵。我説此話你不信，心裏總覺太倒楣。 病 符 — — 命逢病符吞陷星，大病小病總有痛。無災人福辦事難,一天到晚無笑容。 病符主災厄，疾病害難逢。中青無大害，老小藥無力。 病符本是小凶星，就怕再把殺星逢。同柱相配定吉凶，細查旺衰來應用。 病符壓運事難强，事要三思免禍殃。病魔纏身實堪憂,三災八 難難躲藏。 病符為小凶星，主人身體有病，纏綿難愈。 行年病符是凶神，終日悶沈沈。四肢無力，常帶病三分，説你没有 病，好 像身子沈。做些鬼魂夢,忽忽悠悠象駕雲。走些偏僻 與胡同，遇些孤廟舆 孤墳。清晨起來對人言，夢頭夢尾記不真。 主官非病破。病符星君入宫，此年勿入病人家，切不可探病，勿食喪物， 身體不安，謀事不成，願守舊業。免有浮沈不定致破財，宜制化即安，百 事如意，身體康寜，財利亭通。 無孔不人，逢遇之年，身心愁，悶病痛多，遠離 病人，勿食婚喪紅白事， 謹防流行病，回避祭儀。此年應多到廟堂拜佛，少到公共場所，宜 以病符 星君符舆藥方飲之，可保平安。 天喜——天喜是六合，災病字消磨。男人重重喜，女人喜事多。 有妻生貴子，無妻取嬌娥。若是辦點事，别人上趕著。 咸池——情感、性欲、魅力、戀愛、婚姻生活、隱私、陰暗、 酒水類。主容貌秀 麗,沈於酒色，追求享受，性急性巧，有同情心，愛風流，多才蓉、聰 明、倜僕、異性緣佳。或言行狡詐,避蕩淫赌，無所不為。 168 盲派經 學 血刃 命犯血刃有福災,病痛開刀命裏定 。不是心焦眼就跳，總有愁事悶心懷。 車前馬後加防備,他人打仗要躲開。此殺犯之，男血光，女産厄。 女犯河魁一 秉性剛直，急躁剛烈，不聽人勸阻，謹防牢獄之災,婚姻破敗,有潔 癖， 心思露巧。於婚姻有所影響,好勝心強,不遵守法紀。吉凶極端。 亡神— ——亡神入命乎夏憂,活著累挺没勁頭。行車駕驶擔風險,發生車福性命憂。 一年四季耗財氯，外出提防犯財氣。亡神七殺禍非輕,用盡機心一不成。 剋子刑妻無祖業,士人猶恐有虚名。命宮若也值亡神，須是長生逢貴人。 時日更兼天地合，匪躬蹇蹇作王臣。 吞陷殺—— 有進少出多之象，家庭生活也不能平静，須花大量之錢財來章固自己之地 位。但其年福星高照，吉多凶少，只是其年有病星影射，身體欠佳、進取 之時,宜多加小心，否則得不償失，其年始可攻，葳末宜守。主骨肉刑 福。 指背— ——命入指背主大災,把錢借出要不 來。親戚朋友能反目，失信違約命裏該。 他人吃了魚身子，剩下魚頭你去摘。防備賊盗加謹慎，三番二次小人來。 劫殺———劫殺為災不可擋,徒然奔走名利場。须防祖業盡消亡，妻子如何得久長。 寡宿———命中逢之，大多孤樓獨宿，伶仃凄苦，婚姻不 顺，六親淡薄。外鄉之 客 漂泊不定。 天哭——天哭人命主傷財，家中難免哭聲來。暗有 小人把你害，□舌是非找上來。 災煞- 官認刑獄,喪孝破財，口舌是非，祖業飄零，血光横死，牢獄之苦，須防 火燒水溺之災,或棍杖劍刃之傷,舆摔跌墜落及瘟疫 (流行性病毒)之 災。 紅豔———命逢此殺者，生性風流，人見人愛，且漂亮、性温順,處事公平，不奸不 滑。女命浪漫不貞,淫奔私約，富貴難免。 為情多欲少人知，眉開眼笑樂嘻嘻。世間只是器人妻，禰馳相扶作路妓。 任是官家富家女，花前月下亦偷期。 欄杆———命犯欄杆混渾池，財錢支破兩分離。男人犯善招官事，女命犯著時遠近。 不是心焦眼就跳，總有愁事悶心理。時來運轉人欺鬼，運敗時衰鬼欺人。 欄杆之星最凶辰，惡星臨之必見刑。若有吉星同位坐，富 貴榮華百年春。 披頭— ——命犯此恶星者，披麻戴孝之意，防傷損雙親,孝服喪事。此殺須結合 四柱 推斷，知曉舆父母之缘份已盡,或主親人中有死亡之預兆。主有孝 服，若 更值惡星，则孝服不可免。 盲 派 神 煞 訣 169 華蓋 ——血氣方剛,氣傲皇天，性孤少情，六親不靠，自主沈浮，為整術星，聰明 好學,喜歡整術,見解超群，才華非凡，镥畫音樂,吟詩作對。且與宗教 有緣,嚮往淡泊寜静之生活。故多與佛道有缘，或浪跡江湖，同遊四方 或為孤寡之人。 三刑 — — 無禮之刑，因無禮而觸犯刑法，多為感情風波及六親之間之矛盾事件。面 無和顔，氣強性暴，怠慢忽略，心胸狹窄。大多主人傲慢、少孝道，不遵 禮節、六親無情。妨害親子，上下不睦，同僚相妒，多招刑禍。女犯此 刑，則性格暴躁，壓制夫君，母子不睦，易損孕。其災禍多表現在色情方 面。 羊刃——男逢羊刃剋頭妻，女逢傷官夫早離。命中帶有送終子，家中要娶二回妻。 性情剛烈，兇狠好鬥,口快心直，見義勇為,剋妻傷財。女逢羊刃，刑夫 剋子，以怨報德，易招災禍,衝動暴戾，外貌温和，内情執拗，自以為 是。對人探取不信任之態度，主觀意識強，不輕易採納他人之意見,思想 易走極端。 子卯刑——為無禮之刑，因無禮而能犯刑法。多 為感情風波及六親之間的矛盾事件。 刑入羊刃恶殺中，會傷及身體。為人不講孝道，不遵禮節,六親無情，性 情暴戾，上下不睦，同事相妒，或剋損六親之凶兆。 紅 驚——红驚神殺真是合，逢著喜事真正多。男遇紅鶯添人口，女遇紅驚必出閣 。 一年四季求財顺，遠近求財也隨和。犯點説道没 關係，貴人説明無章扯。 天厄———是不吉利，犯之一年困頓，宮職不顯,且有奪官之優,難得提技。犯之定 主危難。 地 殺——不宜接受上級派遣，外出工作、經商、嫁娶、造屋、命中逢此 殺者，會有 死亡災。 命逢勾絞貫索星，平常度日無災生。男怕太陰生口舌，女遇太陰喜事生。 太陰女色星，勾絞染疾病。斜眼看動静，女騙白骨精。 勾絞 ——行年到此，有口舌刑獄之事發生，或退財勾連之事，頻遭編配，災滯 傷 身。勾絞交運,事生煩惱,莫道一勺水，能起百丈風波，男多犯 人害，受 暗中箭，此年中夜間,安拜太陽星君，以保吉祥，有喜無災,百福自來。 太陰星君一 太陽當權,陰盛陽衰，恐貴極反否，女人應注意言行，切勿驕縱逞强， 不宜深夜子時後行夜路，易出事。男人防美人計,防被女人抛棄。每月 二十六日酉時,向西方叩拜太陰星君，將太陰星君符與金紙一同燒化，可 170 盲 派 经 學 保平安吉利： 劍鋒———劍鋒臨門主 大災,禍害口舌是非來。六畜提防人盗走，傷財意氣哭聲來。 親戚朋友不借力，要犯車前馬後關。車前馬後躲過去，刀鐮射斧命裏 該。 伏屍 ——命犯伏屍主凶危，本身不旺要嘲碎。做夢見神 又見鬼，死之活之一大堆。 大鬼請你去吃飯,小鬼請你把客陪。忽然驚醒夢一場,口渴幹來眼發黑。 為膿血，最為兇惡，並之真可畏。若能吉星同 位中，福祢榮昌有職位。 太陽星君一 命逢天空太陽星，貴人到位免災行。出門辦事有人幫,即便有險貴人冲。 太陽本吉星，恐有火症病。男命無大害，女命災禍臨。 吉祥年，過去的黴運之事都被化解， 一掃而空，運氣順暢。正當光明之事 都易成功，雖有財利，不宜冒險投機赌博，免破大財。農層每月二十七日 卯時,向東方拜太陽星君，將此太陽星君符舆金紙一同燒化，可保平安。 天 空 — — 天空入運不顺清，就怕聞氣口舌生。没有口舌怕重孝，傷財惹氣有災星。 四柱官般多太重，若要逢合保太平。人不旺來財不進,賈賣交易落場空。 天空佔宮，休管他人事，莫爭口舌是非，可免是非破財，連累事項。女人 犯此年須防色情，夫妻反睦。出外有財吉利，最好安奉日月照星君，則大 吉 。 晦氟——晦氟臨門不安排，不傷錢財必有災。閉門不出家中坐，是非□舌找上來。 事不找人人找事， 一口惡氯撲上來。千萬別把開事管，要管開事必傷財。 流霞———命遇流霞切需防，葳運逢之見血光。男見流霞他鄉死，女人遇之産後亡。 兒女難養夫妻别，母子不睦逝主凶。應防酒色傷身 。此殺人命犯之，男主 他鄉死，女主産後亡。 驛馬———人命若還逢驛馬,求利求名可發達。貴人馬多多升躍,常人馬多不為佳。 身旺驛馬逢財地，能走鴻運把財發。如果馬頭能带劍,一年奔波且勞苦。 將星 ——將星文武雨相宜，禄重權高定可知。遇此提兵能領将，享有整譽天下知。 将星財寶永無窮,家活生涯事事通。天乙更來天德上，少年平步上天宮。 将星一位最為良，時日相同命必昌。官職容高宣世賞，安邦定國鎮邊疆。 金匱 ——女命逢此，不富則貴;男命逢此，易得福藤，異性缘佳，多 受女子青睞。 孤辰、寡宿 命中逢之，大多孤棲獨宿，伶仃淒苦，婚姻不順,六親淡薄。外鄉之客， 漂泊不定。若命逢之多孤寡，刑害兼須損六親。男逢孤辰須切忌，女逢寡 宿獨眠瞋。 男犯天罡一秉性剛直，不聽人勸阻，謹防牢獄之災,婚姻破敗， 有潔癖，急躁剛烈。 盲 派 神 煞 訣 171 月德——命逢月德主吉昌，天德相配更相當。 一年官刑不會犯，春夏秋冬無災殃。 男女犯命星 婚姻不利。 貫索 ——皆不吉利，主凶多吉少。貫索之星不可當,更兼恶宿最為 殃。三方四正吉 星人，福毒榮華職祿昌。 卒暴——突然病重或夭折。 飛符、暴敗 是非口舌，横禍災至。失敗、落選、自暴自棄。主有孝服，若更值恶星， 則孝服不可免。此二殺主横災官事，惟天月二德解神，可以救免。 黄 幡 - 是非小凶星。 板鞍 ——吉利之星。板鞍在命最為奇，年少登科世所稀。更得官星加冠带，晚年定 有貴男兒。命中帶馬用板鞍，華蓋前當四柱安。管取飛黄腾達去，狀元及 第又何難( 四狱 — — 防牢獄之災 。 天殺、葳殺 皆是掌權之相，亦主兵權。天殺難招父命長,纏綿宿 疾不離床。除非祖業 先磨减，難免此身陷禍殃。天殺加臨冠带鄉,不愁衣著不愁娘。身閑命吉 無災咎，枝葉偏多福禄昌。 六害——兩旺相持必有一傷,此為勢家相害，不利骨肉六親,多為妻妾爭鬥所累 或孤獨無靠。 暴敗——此二殺主横災官事，惟天月二德解神，可以救 免。 八座、解神、地解一天解、地解此二神能解一切凶，能興一切善，化凶為吉。大吉之 神，能逢凶化吉，遇吉呈祥。 月 殺——月殺之神半吉凶，弟兄男女有無中。師巫僧道閑過日，卻主前程命運通 。 月殺加逢自基臨,聰明智慧衆人欽。農商工賈並僧道，營運豐盈名稱心。 捲舌——捲舌凶星為膿血，巧逢吉星最為宜。三方四正星辰旺，富貴榮華百嵗期。 飛廉 此殺逢吉則主權威，逢凶則主横死。 的殺 —— —命犯更坐在惡限，人逢凶星，多主恶死，不然貧窮帶疾徒 配之人。 破碎殺——人命若逢破碎殺,破財恰似湯澆雪。行年運限更加臨,官事連綿 無休止。 陌越——若月用之星逢之減半之力，若殺星逢之，多主恶死，冲之必見官事災晦。 地殺———地殺難招母命長,須知前後唤人娘。若然在家應愁悶,南北 衣資始 大通。 地殺如逢貴祿鄉,若能備學富文章。不然管運多財寶,立業成家大吉昌。 年殺———年殺原來最是凶，不招祖業走西東。重重婚姻無男女，外族 須教破一重。 月空———月空之人亦罕逢，那堪官貴在其中。金麟豈是池中物，不日天書下九重。 172 盲派絕 學 疾病總論 { 生 月 疾 病 } 寅 ( 正月) 感應左腳第四趾，屬絡於左膽足少陽經脈,此月份若本身器官功能失調 時,易口苦。數息，左肋疼痛，轉身困難,若因經脈傅運功能失常，易 造成左偏頭痛，左眼尾區痛癢，左側肢骨關節不靈活，左足第四趾痛或 抽搐。 腳四趾，膽足少陽經脈。左側,病變;哀聲數氣，心肋疼痛、過敏性鼻 炎、踝易扭傷、面带塵色。 卯(二月) 感應左腳小趾，屬絡於左膀胱足太陽經脈。膀胱機能不流暢時,易導致 冲頭痛，左側痛甚於右側。腰酸背痛、小便不利、遺尿、不尿、左髀關 節舉足不露活，左踝酸痛如扭，左膝筋緊難 屈伸。如經脈性功能不佳， 易眼睛發黄、流鼻血、鼻塞、左半邊之頸項、腰、背、以至足、小趾都 疼痛，行動不露活。 腳小趾，膀胱足太陽經脈。左側，病變;排尿、腰尻、膝部、頭頸酸 痛 。 辰(三月) 感應左脚第二、三趾，屬絡於左胃足陽明經脈。胃為五臓六腑之海，人 體之倉,供應養分之總樞紐,如外在因素加迫胃經脈,易 驚嚇、狂躁、 有怕冷之感覺,或在左眼痛、喉痛、腿足發冷。内臓之病變會引起腹 脹、水腫、易饑餓、尿色發黄、足趾和二、三趾皆痛，以左側為最。 腳二、三趾，胃足陽明經絡經脈,口腹之欲，左側,節制食欲。病變; 胃痛、頭痛、易護餓、尿色黄、四肢無力、急躁不安、胃疾難纏。 巳(四月) 感應右腳第二、三趾，屬絡於右胃足陽明經脈。其症狀如辰月，偏右 身。腳二、三趾，胃足陽明經絡經脈,口腹之欲，右側,節制食欲。病 變;胃痛、頭痛、易譏餓、尿色黄、四肢無力、急躁不安、胃疾難纏。 午 ( 五月) 感應右腳小趾，屬絡於右膀胱足太陽經脈。其症状同於卯月，偏右。腳 小趾，膀胱足太陽經脈。右側，病變;排尿、腰尻、膝部、頭頸酸痛。 未(六月) 感應右腳第四趾，屬絡於右膽足少陽經脈。此月若病，其症狀同於寅 月，偏右身側。 腳四趾，膽足少陽經脈。右側,病變;哀聲欺氣，心肋疼痛、過敏性鼻 炎、踝易扭傷、面带塵色。 申(七月) 感應右脚底，屬絡於右臀足少陰經脈。外感病、背部疼痛、腰 痛挺不 174 盲派絕 學 西(八月) 戌(九月) 亥(十月) 子(十一月) 直、兩足發冷無力、口乾咽痛。從解胃、腿後一直到腳底板皆痛，以右 腳為甚。如臀贜本身功能障礙,面部會浮腫而面色如 漆紫，大便困難、 泄瀉、腹脹、陽痿、敗腎。 腳底表征，臀足少陰經脈,右側，病變；腰酸背疼、 女白帶、男早溲。 口臭、咽腫、膝盖及腰腳無力、患腎炎尿毒。 感應右腳大趾内側，屬絡於右脾足太陰經脈·脾經脈迴圈之異常，易使 頭重、體重；舌頭屈伸不自如，四肢肌肉痿 缩，脾臌滯礙、吃不下飯、 心下疼痛 、拉稀泄瀛，不能队，股部至膝蓋内側腫痛，痛 連大趾，以 右 侧區域。 脚大趾内側表征，脾足太陰經脈,右側，病變;易食欲之振、消化不 良、件伴精神恍惚、意志消沈。有時濕疹、 或大趾特别偏向內側之人， 對自己情緒及意志問题，更要小心。叢毛密而濃,肝氯較盛，须自我脾 氣克制。稀 落或無毛，肝氣不足，易疲勞、無精打采。 感應右腳大趾叢毛區,屬絡於右肝足厥陰經脈。致腰痛不可以 俯仰，男 性易有攝護腺腫大之症，女性經帶不順,小腹腫脹之象；肝功能失 調 倦倦劳累，食欲不振，胸满嘔吐、遭尿、不尿。 觀右足，病變;秋冬之交，秋末之燥氟最擾肝，輕微如女經帶不順,男 疝氣，嚴重如肝功能失調,無以解毒，易嘔吐、 泄漓、肝炎、肝硬化、 癌細胞入侵。 感應左脚大趾叢毛區,屬絡於左肝足厥陰經脈,如大趾有莫名的腫痛或 叢毛區突長痘疹，及時治療。 觀左足，病變；秋冬之交，秋末之燥氯最擾肝，輕微如女經帶不順，男 疝氣，嚴重如肝功能失調,無以解毒，易嘔吐、 泄漓、肝炎、肝硬化、 癌細胞入侵。 感應左脚大趾内側，屬絡於左脾足太陰經脈。病症同酉月，陰氯重，偏 左側。脾統於血、血翰氧氣和養分到身體各部。八月與十一月最易餅發 病本經脈之處。 脚大趾内側表征，脾足太陰經脈,左側，病變；易食欲之振、消化不 良、饼伴精神恍惚、意志消沈。有時瀑疹、或大 趾特別偏向内側之人， 對自己情緒及意志問題,更要小心。叢毛密而濃,肝氣較盛，须自我脾 氯克制。稀落或無毛，肝氯不足，易疲勞、無精打采。 疾 病 德 論 175 丑(十二月) 感應左脚底，屬絡於左肾足少陰經脈。症状如申月左側，陽虚需食補養 身，葉補溫陽。 腳底表徵，腎足少陰經脈,左侧，病雙；腰酸背疼、女白帶、男早溲。 口臭、咽腫、膝蓋及腰腳無力、患腎炎尿毒。 (生日疾病} 初一、十一、廿一日——感應左手第四指，絡於左三焦手 少陽經脈,外經病候；咽喉 腫痛、耳痛耳整、局臂外側痛、右側;内朦病狀:腹脹、小便不通、水 腫 。 左右三焦手少陽經脈,主掌人之生命原動力， 生殖系統。手第四指(無 名指 ):子宮、卵巢、精宮、陽九之先天體質與後天病變,如指骨歪斜 扭曲是先天不良，肉質枯槁、表皮長疹，是後天失調或感染 。注意耳 朵、眼睛、手腕之過度疲勞。 初二、十二、廿二日——感應左手第五指外側，絡於左小腸手太陽經脈; 腸經滯塞、口 舌糜爛、臉頰下颚腫痛、眼垢多、局背外側 痛、小指伸不直如扭痛、小 腸吸收蠕動功能失調、小腹脹痛、痛連腰部、痛引至陽丸或陰部、大便 不利、泄瀉。 左右小腸手太陽經脈。飲食：清淡、易消化、定食定量。病變;手小指 骨頭特别外偏、外側時常長疹子或無名腫痛，表症小腸先天舆後天之欠 缺，轉化吸收較差，它之畸型影響”丹田」之蓄力。忌油膩、刺激之食 品，防嗌痛、腹痛、泄漓。 初三、十三、廿三日——感應左手第二指，絡於左大腸手陽明經脈。病變;大腸活動功 能失調:□易燥渴、發熱、齒痛、局胛痛連上臂，身子或紅腫灼熱,覺 得寒冷，手食指無名腫脹、活動不便、大腸轉化失常、易常鳴、腹痛無 定處、大便溏泄、皮膚過敏。 左右大腸手陽明經脈,食指骨質之歪曲，表徵大腸先天之轉化及調節水 分功能之衰弱，易便秘、拉稀、小腹脹痛之排泄不順而引發之病。主左 腹降結腸功能，如先天大腸較脆弱，後天失調而引起上牙痛，皮廣敏 感、呼吸上喘之供發症，第二指易感强烈之麻木、不靈活、僵直、而午 時又血壓偏高，防中風。 初四、十四、廿四日——感應右手第二指，絡於右大腸手陽明經脈。病變;大腸活動功 176 盲派經 學 能失調:口易燥渴、發熱、齒痛、局胛痛連上臂，身子或紅腫灼熱,覺 得寒冷，手食指無名腫脹、活動不便、大腸轉化失常、易常鳴、腹痛無 定處、大便溏泄、皮腐過敏。 初五、十五、廿五日——威應右手第五指外側，络於右小陽手太陽經脈;腸經滯塞、口 舌糜爛、臉頰下颚腫痛、眼屎多、肩背外側 痛、小指伸不直如扭痛、小 腸吸收蠕動功能失調、小腹脹痛、痛連腰部、痛引至陽大或陰部、大便 不利、泄瀉。 初六、十六、廿六日——感應右手第四指，絡於右三焦手少陽 經脈,外經病候；咽喉 腫痛、耳痛耳蟹、局臂外側痛、右側;内臓病状：腹脹、小便不通、水 腫 。 初七、十七、廿七日——感應右手小指内側，絡於右心手少陰經脈。病變；心和小腸不 暢、身熱、頭痛、手心熱而痛、肢端發冷、口渴欲飲。心臓功能不良； 心痛、胸口煩悶、氣息不順、量眩冒金星，易 心臓血管病變,缺足夠血 液、氧、葡萄糖之腦部和身體各肢節。 左右手心少陰經脈,第五指頭如糾扭、易悸喘、胸口悶、心、頭痛、缺 氧、頭昏之心臓不良所引而來之疾，尤其小指太偏内側，緊靠第四指， 或小指内側常脱皮幹澀,或長疹痛癢。須心情輕鬆 ，不過度負荷生理及 心理重量。 初八、十八、甘八日——感應右手大指，絡於 右肺手太陰經脈。病變;肺經外邪所感： 鼻塞、頭痛、胸悶、手臂冷而痛，痛連手指，肺臓 受威染，哮喘、咳 嗽、短氯、咽乾、舌燥、手心發燙、嚴重支氟管炎、肺炎。 左右肺手太陰經脈,易感冒而惡化肺炎、心 肺供發症。大指象征肺臓之 性能，時或無名腫痛，扭傷之感覺。注意肺及上呼吸道，須保持心境愉 悦，心理之壓力適度派遣，生理上之心、肺功能。 總論:平日指、趾特別異様( 红 腫 、麻木、 發癢 、 長 疹 ),指甲上半月 狀，甲質變色。反求其所屬經脈追跳其病本，注意保養。 初九、十九、廿九日——感應左手大指，絡於左肺手太陰經脈。病變；肺經外邪所威： 鼻塞、頭痛、胸悶、手臂冷而痛，痛連手指，肺臓受感染，哮喘、咳 嗽、短氣、咽幹、舌燥、手心發燙、嚴重支氯管炎、肺炎。 初十、二十、三十日——感應左手小指内側，絡於左心手少陰經脈。病變；心和小腸不 锡、身熱、頭痛、手心熱而痛、肢端發冷、口渴欲飲。心臓功能不良； 疾 病 總 論 177 心痛、胸口煩悶、氣息不順、量眩冒 金星 ，易心藤血管病變 ，缺足夠血 液、氧、葡萄糖之腦部和身體各肢節。 {生時疾病} 子時: (膽經脈);膽病。 丑時: (下接肝经脈 );肝功能衰弱。 寅時: (肺经必行 );呼吸器官較弱，易受感染。 卯時: (肺經下接大腸經);大 腸排泄系統不暢。 辰時: (大腸經續胃經 ); 胃消化系統較弱 。 巳時: (胃腎二經相接 ); 消化系統較滯不暢,小心飲食。 午時: (主心經脈 ) ; 心 臓、血管。 未時: (小腸經 脈);小 腸較弱。 申時: (膀胱經脈 );膀胱衰弱，較易感染。 西時: (督經 脈);腎功能較弱 。 戌時: (包络經脈 ) ; 心 血管易病。 亥時: 